LOG_RETENTION_DAYS = 7   # Auto-delete log files older than this many days

def _cleanup_old_logs(log_dir, retention_days=LOG_RETENTION_DAYS):
    """Delete log files older than retention_days from log_dir."""
    try:
        cutoff = datetime.now() - timedelta(days=retention_days)
        for fname in os.listdir(log_dir):
            if not fname.startswith("jcfalert_") or not fname.endswith(".log"):
                continue
            fpath = os.path.join(log_dir, fname)
            try:
                mtime = datetime.fromtimestamp(os.path.getmtime(fpath))
                if mtime < cutoff:
                    os.remove(fpath)
            except Exception:
                pass
    except Exception:
        pass

def _setup_logging():
    """Set up logging — file handler when filesystem is writable, console-only otherwise (e.g. Vercel)."""
    global LOG_DIR
    logger = logging.getLogger("jcfalert")
    logger.setLevel(logging.INFO)
    fmt = logging.Formatter("%(asctime)s [%(levelname)s] %(message)s", datefmt="%Y-%m-%d %H:%M:%S")
    if not logger.handlers:
        # Always add a stream (console) handler — works everywhere including Vercel
        sh = logging.StreamHandler()
        sh.setFormatter(fmt)
        logger.addHandler(sh)
        # Try to add a file handler; silently skip if filesystem is read-only
        _file_handler_added = False
        for _dir in [LOG_DIR, _FALLBACK_LOG_DIR, "/tmp"]:
            try:
                os.makedirs(_dir, exist_ok=True)
                _cleanup_old_logs(_dir)
                log_path = os.path.join(_dir, "jcfalert_" + datetime.now().strftime("%Y%m%d") + ".log")
                fh = logging.FileHandler(log_path, encoding="utf-8")
                fh.setFormatter(fmt)
                logger.addHandler(fh)
                LOG_DIR = _dir
                _file_handler_added = True
                break
            except Exception:
                continue
        if not _file_handler_added:
            logger.info("File logging unavailable (read-only filesystem) — logging to console only.")
    return logger

_log = _setup_logging()
_log.info("JCF Alert News Dashboard starting up")

