# fpdf2 import — with Windows path fix for cases where app runs as admin
# but fpdf2 is installed in user site-packages (AppData\Roaming\Python)
PDF_OK = False
_fpdf2 = False
FPDF = None
def _load_fpdf():
    """Load fpdf2 — auto-installs if missing, handles Windows path issues."""
    global PDF_OK, _fpdf2, FPDF
    import sys, os, subprocess

    def _try_import():
        """Try to import fpdf and return (success, FPDF_class, version_str, is_V1)."""
        try:
            import importlib
            # Force reimport in case sys.path changed
            if 'fpdf' in sys.modules:
                importlib.reload(sys.modules['fpdf'])
            import fpdf as _fm
            from fpdf import FPDF as _cls
            _ver = getattr(_fm, "__version__", "") or getattr(_fm, "FPDF_VERSION", "") or ""
            try:
                _f2 = int(str(_ver).split(".")[0]) >= 2 if _ver else False
            except Exception:
                _f2 = False
            if not _f2:
                try:
                    import inspect
                    _f2 = "dest" not in str(inspect.signature(_cls.output))
                except Exception:
                    pass
            return True, _cls, _ver, _f2
        except ImportError:
            return False, None, "", False

    # Step 1: add all possible Windows user site-package paths
    try:
        import site
        for sp in [site.getusersitepackages(), site.getsitepackages()[0] if site.getsitepackages() else None]:
            if sp and sp not in sys.path and os.path.isdir(sp):
                sys.path.insert(0, sp)
    except Exception:
        pass
    try:
        home = os.path.expanduser("~")
        for py_ver in ["Python310", "Python311", "Python312", "Python39", "Python38"]:
            for base in ["AppData\\Roaming\\Python", "AppData\\Local\\Python"]:
                candidate = os.path.join(home, base, py_ver, "site-packages")
                if os.path.isdir(candidate) and candidate not in sys.path:
                    sys.path.insert(0, candidate)
    except Exception:
        pass

    # Step 2: try import
    ok, cls, ver, f2 = _try_import()
    if ok:
        FPDF, PDF_OK, _fpdf2 = cls, True, f2
        print(f"[PDF] fpdf2 loaded OK — version={ver!r} fpdf2={f2}")
        return

    # Step 3: auto-install using THIS Python executable, then retry
    print(f"[PDF] fpdf2 not found — attempting auto-install using {sys.executable}")
    try:
        result = subprocess.run(
            [sys.executable, "-m", "pip", "install", "fpdf2", "Pillow", "--quiet"],
            capture_output=True, text=True, timeout=120
        )
        print(f"[PDF] pip stdout: {result.stdout.strip()}")
        if result.returncode == 0:
            print("[PDF] fpdf2 installed successfully — reloading...")
            ok, cls, ver, f2 = _try_import()
            if ok:
                FPDF, PDF_OK, _fpdf2 = cls, True, f2
                print(f"[PDF] fpdf2 now loaded — version={ver!r}")
                return
        else:
            print(f"[PDF] pip failed (rc={result.returncode}): {result.stderr.strip()}")
    except Exception as install_err:
        print(f"[PDF] Auto-install failed: {install_err}")

    # Step 4: give up — log helpful info
    PDF_OK, _fpdf2, FPDF = False, False, None
    print(f"[PDF] FAILED — fpdf2 could not be loaded or installed")
    print(f"[PDF] Python executable: {sys.executable}")
    print(f"[PDF] Manual fix: run this exact command in PowerShell:")
    print(f'[PDF]   & "{sys.executable}" -m pip install fpdf2')

_load_fpdf()


