@app.after_request
def _gzip_response(response):
    """Gzip compress JSON/HTML for faster frontend on laptop/slow LAN."""
    import gzip as _gz2
    ae = request.headers.get('Accept-Encoding', '')
    if 'gzip' not in ae: return response
    ct = response.content_type or ''
    if not any(t in ct for t in ('json','html','javascript','text')): return response
    data = response.get_data()
    if len(data) < 1400: return response
    comp = _gz2.compress(data, compresslevel=6)
    if len(comp) >= len(data): return response
    response.set_data(comp)
    response.headers['Content-Encoding'] = 'gzip'
    response.headers['Vary'] = 'Accept-Encoding'
    response.headers['Content-Length'] = len(comp)
    return response
