POS_WORDS = set("good great excellent wonderful fantastic amazing positive growth rise boost profit gain success win record high achievement improvement surge recovery launch expand benefit strong rally advance approve celebrate award breakthrough innovation progress develop invest opportunity optimistic best leading champion victory triumph prosper".split())
NEG_WORDS = set("bad poor terrible horrible awful negative loss decline fall drop crash deficit debt default crisis recession inflation risk threat danger warning alert attack violence conflict war tension dispute protest strike ban block slow weak bear slump fraud scam scandal corrupt illegal arrest accused charge injury death disaster flood drought fire earthquake abuse fail collapse".split())
HIGH_PRIORITY_WORDS = set("urgent emergency critical breaking alert disaster attack explosion bomb flood cyclone death killed fire evacuate crisis warning".split())
MED_PRIORITY_WORDS  = set("accident injured damage closed blocked disrupted delayed cancelled protest strike dispute conflict tension".split())

def get_sentiment(text):
    if not text: return "neutral", 0.0
    words = re.findall(r'\b[a-z]+\b', text.lower())
    pos = sum(1 for w in words if w in POS_WORDS)
    neg = sum(1 for w in words if w in NEG_WORDS)
    total = pos + neg
    if total == 0: return "neutral", 0.0
    score = (pos - neg) / max(total, 1)
    if score > 0.1: return "positive", round(score, 3)
    if score < -0.1: return "negative", round(score, 3)
    return "neutral", round(score, 3)

def detect_cities(text):
    """Return matched India cities, or ['india'] if none found."""
    if not text: return ['india']
    t = text.lower()
    found = list({c for c in sorted(INDIA_CITIES, key=len, reverse=True)
                  if re.search(r'\b' + re.escape(c) + r'\b', t)})
    return found if found else ['india']

def detect_category(text):
    if not text: return "Other"
    t = text.lower()
    for cat, kws in CATEGORY_KEYWORDS.items():
        if any(k in t for k in kws):
            return cat
    return "Other"

def detect_priority(text):
    if not text: return "Low"
    t = text.lower()
    words = set(re.findall(r'\b[a-z]+\b', t))
    if words & HIGH_PRIORITY_WORDS: return "High"
    if words & MED_PRIORITY_WORDS:  return "Medium"
    return "Low"

# Stop words excluded from topic word count
_STOP_WORDS = frozenset("a an the in on at of to for is are was were be been being have has had "
                        "do does did will would could should may might shall can this that these "
                        "those with by from as into through during before after above below and "
                        "or but not its it we they he she i you".split())

def topic_matches(topic, text):
    """
    Smart multi-word matching:
    - Skip stop words when counting topic words
    - 1 word → need 1 match
    - 2 words → need 2 matches  
    - 3 words → need 2 matches (67%)
    - 4+ words → need ceil(0.67 * N) matches
    """
    if not topic or not text: return False
    t = text.lower()
    words = [w for w in re.findall(r'[a-z]+', topic.lower())
             if w not in _STOP_WORDS and len(w) > 1]
    if not words: return False
    n = len(words)
    required = n if n <= 2 else max(2, math.ceil(n * 0.67))
    matched = sum(1 for w in words if re.search(r'\b' + re.escape(w) + r'\b', t))
    return matched >= required

def hash_pw(pw):
    return hashlib.sha256(pw.encode()).hexdigest()

def detect_device_info(user_agent_str):
    """Parse User-Agent string to extract device type, OS, and browser."""
    ua = (user_agent_str or '').lower()
    # Device type
    if any(x in ua for x in ['iphone', 'android', 'mobile', 'blackberry', 'windows phone']):
        if 'tablet' in ua or 'ipad' in ua:
            device_type = 'Tablet'
        else:
            device_type = 'Phone'
    elif 'ipad' in ua:
        device_type = 'Tablet'
    elif any(x in ua for x in ['macintosh', 'mac os x']):
        device_type = 'Mac'
    elif 'windows' in ua:
        device_type = 'Laptop/PC'
    elif 'linux' in ua:
        device_type = 'Linux'
    else:
        device_type = 'Unknown'
    # OS
    if 'iphone' in ua or ('ipad' in ua):
        os_name = 'iOS'
    elif 'android' in ua:
        os_name = 'Android'
    elif 'windows phone' in ua:
        os_name = 'Windows Phone'
    elif 'windows' in ua:
        os_name = 'Windows'
    elif 'macintosh' in ua or 'mac os x' in ua:
        os_name = 'macOS'
    elif 'linux' in ua:
        os_name = 'Linux'
    else:
        os_name = 'Unknown'
    # Browser
    if 'edg/' in ua or 'edge/' in ua:
        browser = 'Edge'
    elif 'opr/' in ua or 'opera' in ua:
        browser = 'Opera'
    elif 'chrome/' in ua and 'chromium' not in ua:
        browser = 'Chrome'
    elif 'firefox/' in ua:
        browser = 'Firefox'
    elif 'safari/' in ua and 'chrome' not in ua:
        browser = 'Safari'
    else:
        browser = 'Unknown'
    return device_type, os_name, browser

def get_today_ist():
    return (datetime.now(timezone.utc) + timedelta(hours=5, minutes=30)).strftime("%Y-%m-%d")

def now_ist():
    return (datetime.now(timezone.utc) + timedelta(hours=5, minutes=30)).strftime("%Y-%m-%d %H:%M")

def parse_date(ds):
    if not ds:
        return datetime.now(timezone.utc).isoformat(), now_ist()
    for fmt in ["%a, %d %b %Y %H:%M:%S %z", "%a, %d %b %Y %H:%M:%S GMT",
                "%Y-%m-%dT%H:%M:%S%z", "%Y-%m-%dT%H:%M:%SZ", "%d %b %Y %H:%M:%S %z"]:
        try:
            dt = datetime.strptime(ds.strip(), fmt)
            if dt.tzinfo is None: dt = dt.replace(tzinfo=timezone.utc)
            ist = dt + timedelta(hours=5, minutes=30)
            return dt.isoformat(), ist.strftime("%Y-%m-%d %H:%M")
        except: pass
    return datetime.now(timezone.utc).isoformat(), now_ist()

# ══════════════════════════════════════════════════════════════════════════════
# DATABASE ABSTRACTION
# Supports both MSSQL (pyodbc) and SQLite with identical interface
# ══════════════════════════════════════════════════════════════════════════════
_db_lock = threading.Lock()

def _ensure_db_exists():
    """Create jcf_news database on SQL Server if it does not exist."""
    try:
        master_cs = (f"DRIVER={{{DB_CONFIG['driver']}}};"
                     f"SERVER={DB_CONFIG['server']},{DB_CONFIG['port']};"
                     f"DATABASE=master;UID={DB_CONFIG['username']};PWD={DB_CONFIG['password']};"
                     f"TrustServerCertificate=yes;Connection Timeout=3;")
        conn = pyodbc.connect(master_cs, timeout=10, autocommit=True)
        cur = conn.cursor()
        db = DB_CONFIG['database']
        cur.execute(f"IF NOT EXISTS(SELECT name FROM sys.databases WHERE name=N'{db}') CREATE DATABASE [{db}]")
        conn.close()
    except Exception as e:
        print(f"[DB] ensure_db: {e}")

def _check_net_status():
    """Check internet connectivity."""
    if not REQUESTS_OK: return "disconnected"
    try:
        req_lib.get("https://www.google.com", timeout=4)
        return "connected"
    except:
        return "disconnected"

def _get_sqlite_fallback():
    """Return a SQLite connection as fallback when MSSQL is unavailable."""
    global DB_PATH
    # Ensure DB_PATH is writable — fall back to /tmp on read-only filesystems (e.g. Vercel)
    try:
        os.makedirs(os.path.dirname(DB_PATH) if os.path.dirname(DB_PATH) else ".", exist_ok=True)
        _probe = DB_PATH + ".probe"
        open(_probe, "a").close()
        os.remove(_probe)
    except OSError:
        DB_PATH = "/tmp/news_fallback.db"
    conn = _sqlite3.connect(DB_PATH, timeout=30, check_same_thread=False)
    conn.row_factory = _sqlite3.Row
    conn.execute("PRAGMA journal_mode=WAL")
    conn.execute("PRAGMA busy_timeout=30000")
    conn.execute("PRAGMA synchronous=NORMAL")
    # Ensure tables exist in SQLite fallback
    c = conn.cursor()
    c.execute("""CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT, username TEXT UNIQUE NOT NULL,
        password_hash TEXT NOT NULL, full_name TEXT DEFAULT '', role TEXT DEFAULT 'viewer',
        is_active INTEGER DEFAULT 1, created_at TEXT, last_login TEXT)""")
    c.execute("""CREATE TABLE IF NOT EXISTS articles (
        id TEXT PRIMARY KEY, title TEXT, description TEXT, link TEXT, source TEXT,
        pub_date TEXT, pub_date_ist TEXT, sentiment TEXT, sentiment_score REAL,
        cities TEXT, topics TEXT, category TEXT DEFAULT 'Other', priority TEXT DEFAULT 'Low',
        is_urgent INTEGER DEFAULT 0, is_read INTEGER DEFAULT 0, is_alert INTEGER DEFAULT 0,
        person TEXT DEFAULT '', ai_verified TEXT DEFAULT 'pending',
        ai_verdict TEXT DEFAULT '', created_at TEXT)""")
    c.execute("""CREATE TABLE IF NOT EXISTS favorites (
        id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER, article_id TEXT,
        created_at TEXT, UNIQUE(user_id, article_id))""")
    c.execute("""CREATE TABLE IF NOT EXISTS notifications (
        id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER,
        title TEXT, body TEXT, priority TEXT DEFAULT 'Low',
        is_read INTEGER DEFAULT 0, created_at TEXT)""")
    c.execute("""CREATE TABLE IF NOT EXISTS topics (
        id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT UNIQUE, created_at TEXT)""")
    c.execute("""CREATE TABLE IF NOT EXISTS settings (skey TEXT PRIMARY KEY, svalue TEXT)""")
    c.execute("""CREATE TABLE IF NOT EXISTS custom_feeds (
        id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL,
        url TEXT UNIQUE NOT NULL, is_active INTEGER DEFAULT 1, created_at TEXT)""")
    # Default users
    if not c.execute("SELECT 1 FROM users WHERE username='admin'").fetchone():
        c.execute("INSERT INTO users (username,password_hash,full_name,role,is_active,created_at) VALUES (?,?,?,?,1,?)",
                  ('admin', hash_pw('admin@123'), 'Administrator', 'admin', datetime.now().isoformat()))
    if not c.execute("SELECT 1 FROM users WHERE username='icomply'").fetchone():
        c.execute("INSERT INTO users (username,password_hash,full_name,role,is_active,created_at) VALUES (?,?,?,?,1,?)",
                  ('icomply', hash_pw('m00se@123'), 'Support', 'admin', datetime.now().isoformat()))
    conn.commit()
    return conn

_mssql_last_fail_time = 0   # timestamp of last MSSQL failure
_MSSQL_RETRY_INTERVAL = 30  # seconds before retrying MSSQL after failure

def get_db():
    """Return DB connection: MSSQL preferred, SQLite fallback if MSSQL fails.
    After a failure, skips MSSQL for _MSSQL_RETRY_INTERVAL seconds so requests
    don't hang on timeouts — making login and all API calls instant during outage."""
    global _db_status, _using_sqlite_fallback, _mssql_last_fail_time
    if PYODBC_OK and USE_MSSQL:
        # Skip MSSQL attempt if we recently failed (avoid 20-40 sec timeout per request)
        elapsed = time.time() - _mssql_last_fail_time
        if _using_sqlite_fallback and elapsed < _MSSQL_RETRY_INTERVAL:
            _db_status.update({"status":"disconnected","error":"SQLite fallback active","ts":now_ist()})
            return _get_sqlite_fallback()
        try:
            _ensure_db_exists()
            cs = (f"DRIVER={{{DB_CONFIG['driver']}}};"
                  f"SERVER={DB_CONFIG['server']},{DB_CONFIG['port']};"
                  f"DATABASE={DB_CONFIG['database']};"
                  f"UID={DB_CONFIG['username']};PWD={DB_CONFIG['password']};"
                  f"TrustServerCertificate=yes;Connection Timeout=3;")
            conn = pyodbc.connect(cs, timeout=4)
            conn.autocommit = False
            if _using_sqlite_fallback:
                print("[DB] MSSQL reconnected — resuming primary DB")
                _using_sqlite_fallback = False
                _mssql_last_fail_time = 0
            _db_status.update({"status":"connected","error":"","ts":now_ist()})
            return conn
        except Exception as e:
            _mssql_last_fail_time = time.time()
            _db_status.update({"status":"disconnected","error":str(e)[:100],"ts":now_ist()})
            if not _using_sqlite_fallback:
                print(f"[DB] MSSQL unavailable ({str(e)[:60]}), using SQLite fallback")
                _using_sqlite_fallback = True
    # SQLite fallback
    _db_status.update({"status":"disconnected","error":"SQLite fallback active","ts":now_ist()})
    return _get_sqlite_fallback()

def is_mssql(conn):
    """True if connection is pyodbc (MSSQL), False if sqlite3."""
    return hasattr(conn, 'autocommit')

def db_execute(conn, sql, params=(), fetchone=False, fetchall=False):
    """Unified execute that handles both MSSQL and SQLite."""
    if USE_MSSQL:
        # Convert ? placeholders to ? (pyodbc uses ?)
        cur = conn.cursor()
        cur.execute(sql, params)
        if fetchone:
            row = cur.fetchone()
            if row is None: return None
            # Return as dict-like
            cols = [d[0] for d in cur.description]
            return dict(zip(cols, row))
        if fetchall:
            cols = [d[0] for d in cur.description]
            return [dict(zip(cols, r)) for r in cur.fetchall()]
        return cur
    else:
        cur = conn.execute(sql, params)
        if fetchone: return cur.fetchone()
        if fetchall: return cur.fetchall()
        return cur

def mssql_sql(sql):
    """Convert SQLite SQL to MSSQL compatible if needed."""
    if not USE_MSSQL: return sql
    sql = sql.replace("INSERT OR IGNORE INTO", "IF NOT EXISTS INSERT INTO")
    sql = sql.replace("INSERT OR REPLACE INTO", "MERGE INTO")  # simplified
    sql = sql.replace("AUTOINCREMENT", "IDENTITY(1,1)")
    sql = sql.replace("INTEGER PRIMARY KEY AUTOINCREMENT", "INT PRIMARY KEY IDENTITY(1,1)")
    return sql

