def article_id(title, link):
    return hashlib.md5((title + link).encode()).hexdigest()

# ══════════════════════════════════════════════════════════════════════════════
# RSS FETCH
# ══════════════════════════════════════════════════════════════════════════════
last_fetch_time = None

# ── Feed Health Tracker ─────────────────────────────────────────────────────
# Tracks failures per URL. After FEED_FAIL_LIMIT consecutive failures,
# the feed is temporarily disabled until next app restart.
_feed_health = {}   # {url: {"failures": int, "disabled": bool, "last_ok": datetime|None}}
FEED_FAIL_LIMIT = 5      # consecutive failures before disabling
FEED_MAX_RETRIES = 2     # retries per fetch cycle
FEED_RETRY_DELAY = 1.5   # seconds between retries

# Source trust levels for AI verification scoring
# Higher = more credible source; influences verdict confidence boost
SOURCE_TRUST = {
    # Tier 1 — High credibility (national/international established outlets)
    'the hindu': 90, 'ndtv': 85, 'india today': 85, 'hindustan times': 82,
    'times of india': 80, 'economic times': 82, 'mint': 82, 'the wire': 80,
    'reuters': 95, 'ap': 95, 'bbc': 92, 'who news': 95, 'pib': 88,
    'sebi': 90, 'rbi': 90, 'gdacs': 90, 'reliefweb': 88,
    'indian express': 82, 'ndtv business': 82, 'ndtv top stories': 82,
    # Tier 2 — Regional/good credibility
    'zee news': 68, 'india tv': 62, 'rediff news': 60, 'google news india': 72,
    'google news world': 72, 'yahoo news world': 65, 'bing news india': 65,
    'deccan herald': 72, 'deccan chronicle': 68, 'greater kashmir': 65,
    'telangana today': 68, 'odisha tv': 65, 'asianet news kerala': 65,
    'public tv karnataka': 62, 'tv9 telugu': 62, 'tv9 kannada': 62,
    'tv9 marathi': 62, 'tv9 gujarati': 62, 'ntv telugu': 60, 'v6 news': 58,
    'thanthi tv': 60, '24 news malayalam': 60, 'zee 24 ghanta': 60,
    'hescom power news': 72, 'bescom power cut news': 72, 'mescom power news': 72,
    # Tier 3 — Aggregators / blogs / ecommerce (lower credibility)
    'amazon fresh india': 45, 'flipkart minutes': 45, 'grofers milkbasket': 45,
    'jiomart updates': 45, 'bigbasket blog': 40, 'zepto blog': 40,
    'ap disaster alerts': 75, 'karnataka disaster alerts': 75,
    'kerala disaster alerts': 75, 'gdacs disaster': 85,
}

def _get_source_trust(source_name: str) -> int:
    """Return trust score (0-100) for a source. Default 50 for unknown sources."""
    sn = (source_name or '').lower()
    for key, score in SOURCE_TRUST.items():
        if key in sn:
            return score
    return 50  # unknown source — neutral

def _record_feed_failure(url: str, source_name: str):
    if url not in _feed_health:
        _feed_health[url] = {"failures": 0, "disabled": False, "last_ok": None}
    _feed_health[url]["failures"] += 1
    if _feed_health[url]["failures"] >= FEED_FAIL_LIMIT:
        _feed_health[url]["disabled"] = True
        _log.warning(f"[FeedHealth] DISABLED after {FEED_FAIL_LIMIT} failures: {source_name}")

def _record_feed_success(url: str):
    _feed_health[url] = {"failures": 0, "disabled": False, "last_ok": datetime.now()}

def _log_feed_health_db(name: str, url: str, status: str, failures: int,
                         items: int = 0, error: str = ''):
    """Persist one feed health record to the feed_health_log SQL table.
    Runs in a background thread so it never slows down the fetch cycle."""
    def _write():
        try:
            trust = _get_source_trust(name)
            now = datetime.now().isoformat()
            conn = get_db()
            try:
                if USE_MSSQL:
                    cur = conn.cursor()
                    cur.execute(
                        "INSERT INTO feed_health_log (feed_name,feed_url,status,failures,"
                        "items_fetched,trust_score,error_msg,checked_at) VALUES (?,?,?,?,?,?,?,?)",
                        (name, url, status, failures, items, trust, error[:500], now))
                    # Keep only last 500 rows per feed to avoid bloat
                    cur.execute(
                        "DELETE FROM feed_health_log WHERE feed_url=? AND id NOT IN "
                        "(SELECT TOP 500 id FROM feed_health_log WHERE feed_url=? ORDER BY id DESC)",
                        (url, url))
                else:
                    conn.execute(
                        "INSERT INTO feed_health_log (feed_name,feed_url,status,failures,"
                        "items_fetched,trust_score,error_msg,checked_at) VALUES (?,?,?,?,?,?,?,?)",
                        (name, url, status, failures, items, trust, error[:500], now))
                    # Keep only last 500 rows per feed
                    conn.execute(
                        "DELETE FROM feed_health_log WHERE feed_url=? AND id NOT IN "
                        "(SELECT id FROM feed_health_log WHERE feed_url=? ORDER BY id DESC LIMIT 500)",
                        (url, url))
                conn.commit()
            finally:
                conn.close()
        except Exception as _dbe:
            _log.debug(f"[FeedHealthDB] write error: {_dbe}")
    threading.Thread(target=_write, daemon=True).start()

def _parse_rss_xml_safe(content: bytes, source_name: str):
    """Parse RSS XML content safely. Returns list of item dicts or []."""
    import feedparser as _fp
    # First try feedparser (handles Atom, RSS 1/2, namespaces, bozo XML)
    try:
        feed = _fp.parse(content)
        if feed.entries:
            items = []
            for entry in feed.entries:
                title = (entry.get('title') or '').strip()
                if not title: continue
                link = entry.get('link') or entry.get('id') or ''
                summary = entry.get('summary') or entry.get('description') or ''
                summary = re.sub('<[^>]+>', '', summary)[:500]
                pub = entry.get('published') or entry.get('updated') or ''
                items.append({'title': html_mod.unescape(title), 'link': link,
                              'description': html_mod.unescape(summary),
                              'source': source_name, 'pub_date_raw': pub})
            return items
    except Exception:
        pass
    # Fallback: manual ET parse (faster for simple RSS 2.0)
    try:
        try:
            root = ET.fromstring(content)
        except ET.ParseError:
            # Strip encoding declaration that confuses ET
            cleaned = re.sub(rb'<\?xml[^?]*\?>', b'', content, count=1)
            root = ET.fromstring(cleaned)
        channel = root.find('.//channel') or root
        items = []
        for item in channel.findall('.//item'):
            def gt(tag):
                el = item.find(tag)
                return html_mod.unescape(el.text.strip()) if el is not None and el.text else ''
            title = gt('title')
            if not title: continue
            items.append({'title': title, 'link': gt('link') or gt('guid'),
                          'description': re.sub('<[^>]+>', '', gt('description'))[:500],
                          'source': source_name, 'pub_date_raw': gt('pubDate') or gt('published')})
        return items
    except Exception:
        _log.debug(f"[RSS] {source_name}: XML parse error — skipping")
        return []

def fetch_feed(url, source_name):
    """Fetch RSS with: feed health check → cloudscraper → retry → safe XML parse → store."""
    # ── 1. Feed health check ──────────────────────────────────────────────────
    fh = _feed_health.get(url, {})
    if fh.get("disabled"):
        _log.debug(f"[RSS] {source_name}: SKIPPED (feed disabled after repeated failures)")
        return []

    _HEADERS = {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                      "AppleWebKit/537.36 (KHTML, like Gecko) "
                      "Chrome/122.0.0.0 Safari/537.36",
        "Accept": "application/rss+xml,application/xml,text/xml,*/*;q=0.8",
        "Accept-Language": "en-US,en;q=0.9",
    }

    last_err = None
    for attempt in range(1, FEED_MAX_RETRIES + 2):  # +2 because range is exclusive
        # ── 2. Fetch ── try requests first, cloudscraper on 403/429 ───────────
        content = None
        try:
            if REQUESTS_OK:
                r = req_lib.get(url, timeout=12, headers=_HEADERS, allow_redirects=True)
                if r.status_code == 200:
                    content = r.content
                elif r.status_code in (403, 429, 503):
                    # Try cloudscraper to bypass bot protection
                    try:
                        import cloudscraper as _cs
                        _sc = _cs.create_scraper(browser={"browser":"chrome","platform":"windows","mobile":False})
                        cr = _sc.get(url, headers=_HEADERS, timeout=15)
                        if cr.status_code == 200:
                            content = cr.content
                        else:
                            last_err = f"HTTP {cr.status_code}"
                    except Exception as _cse:
                        last_err = f"cloudscraper: {_cse}"
                elif r.status_code == 404:
                    _log.warning(f"[RSS] {source_name}: 404 Not Found — {url}")
                    _record_feed_failure(url, source_name)
                    _log_feed_health_db(source_name, url, 'error', _feed_health.get(url,{}).get('failures',1), 0, 'HTTP 404')
                    return []
                elif r.status_code in (410, 451):
                    _log.warning(f"[RSS] {source_name}: HTTP {r.status_code} (gone) — {url}")
                    _feed_health[url] = {"failures": FEED_FAIL_LIMIT, "disabled": True, "last_ok": None}
                    _log_feed_health_db(source_name, url, 'disabled', FEED_FAIL_LIMIT, 0, f'HTTP {r.status_code} — permanently gone')
                    return []
                else:
                    last_err = f"HTTP {r.status_code}"
        except req_lib.exceptions.ConnectionError:
            last_err = "Connection error"
        except req_lib.exceptions.Timeout:
            last_err = "Timeout"
        except Exception as e:
            last_err = str(e)

        # ── 3. Parse if we got content ────────────────────────────────────────
        if content and len(content) >= 30:
            items = _parse_rss_xml_safe(content, source_name)
            if items:
                _record_feed_success(url)
                _log_feed_health_db(source_name, url, 'ok', 0, len(items))
                if attempt > 1:
                    _log.info(f"[RSS] {source_name}: OK on retry {attempt} — {len(items)} items")
                return items
            # Parsed but no items — not a failure, just empty feed
            _record_feed_success(url)
            _log_feed_health_db(source_name, url, 'empty', 0, 0)
            return []

        # ── 4. Retry ──────────────────────────────────────────────────────────
        if attempt <= FEED_MAX_RETRIES:
            time.sleep(FEED_RETRY_DELAY)

    # All retries exhausted
    if last_err:
        _log.warning(f"[RSS] {source_name}: {last_err} — {url}")
    _record_feed_failure(url, source_name)
    _fh = _feed_health.get(url, {})
    _status = 'disabled' if _fh.get('disabled') else 'error'
    _log_feed_health_db(source_name, url, _status, _fh.get('failures', 1), 0, str(last_err or '')[:200])
    return []

def get_custom_feeds_from_db():
    """Return list of (name, url) from custom_feeds table."""
    try:
        conn = get_db()
        try:
            cur = conn.cursor()
            cur.execute("SELECT name, url FROM custom_feeds WHERE is_active=1")
            return [(r[0], r[1]) for r in cur.fetchall()]
        finally: conn.close()
    except: return []

def fetch_all_feeds():
    global last_fetch_time
    all_items = []
    all_feeds = list(RSS_FEEDS) + get_custom_feeds_from_db()
    _log.info(f"[Fetch] Starting: {len(all_feeds)} feeds")
    # Fetch feeds in parallel for speed
    from concurrent.futures import ThreadPoolExecutor, as_completed
    def _fetch_one(feed):
        sname, url = feed
        results = fetch_feed(url, sname)
        if results:
            _log.info(f"[RSS] {sname}: {len(results)} items")
        return [(sname, item) for item in results]
    with ThreadPoolExecutor(max_workers=20) as ex:
        futures = {ex.submit(_fetch_one, f): f for f in all_feeds}
        for fut in as_completed(futures):
            try: all_items.extend(fut.result())
            except: pass
    inserted = 0
    with _db_lock:
        conn = get_db()
        try:
            mssql = is_mssql(conn)
            if mssql:
                cur = conn.cursor()
                topics_rows = cur.execute("SELECT name FROM topics").fetchall()
                topics = [r[0] for r in topics_rows]
            else:
                topics = [r['name'] for r in conn.execute("SELECT name FROM topics").fetchall()]
            notif_batch = []
            for sname, item in all_items:
                aid = article_id(item['title'], item['link'])
                if mssql:
                    cur = conn.cursor()
                    cur.execute("SELECT 1 FROM articles WHERE id=?", (aid,))
                    if cur.fetchone(): continue
                else:
                    if conn.execute("SELECT 1 FROM articles WHERE id=?", (aid,)).fetchone(): continue
                pub_utc, pub_ist = parse_date(item['pub_date_raw'])
                full = item['title'] + ' ' + item['description']
                sent, score = get_sentiment(full)
                cities = detect_cities(full)
                matched = [t for t in topics if topic_matches(t, full)]
                cat = detect_category(full)
                pri = detect_priority(full)
                is_urgent = 1 if pri == "High" else 0
                insert_sql = """INSERT INTO articles
                    (id,title,description,link,source,pub_date,pub_date_ist,
                     sentiment,sentiment_score,cities,topics,category,priority,is_urgent,created_at)
                    VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)"""
                vals = (aid, item['title'], item['description'], item['link'], item['source'],
                        pub_utc, pub_ist, sent, score, json.dumps(cities), json.dumps(matched),
                        cat, pri, is_urgent, datetime.now().isoformat())
                if mssql:
                    cur.execute(insert_sql, vals)
                else:
                    try: conn.execute("INSERT OR IGNORE INTO articles " + insert_sql[insert_sql.find("("):], vals)
                    except: pass
                inserted += 1
                if is_urgent:
                    notif_batch.append((item['title'][:200], (item['description'] or '')[:300], pri, matched))
            # Notifications for topic-matched urgent articles
            if notif_batch:
                has_t = bool(topics)
                for ntitle, nbody, npri, nmatched in notif_batch[:20]:
                    if has_t and not nmatched: continue
                    if mssql:
                        conn.cursor().execute("INSERT INTO notifications (user_id,title,body,priority,created_at) VALUES (0,?,?,?,?)",
                                             (ntitle, nbody, npri, now_ist()))
                    else:
                        conn.execute("INSERT INTO notifications (user_id,title,body,priority,created_at) VALUES (0,?,?,?,?)",
                                     (ntitle, nbody, npri, now_ist()))
            conn.commit()
        except Exception as e:
            _log.error(f"[RSS] DB write error: {e}")
            try: conn.rollback()
            except: pass
        finally:
            conn.close()
    last_fetch_time = datetime.now()
    total_feeds = len(list(RSS_FEEDS) + get_custom_feeds_from_db()) if inserted > 0 else 0
    _log.info(f"[Fetch] Complete: +{inserted} new articles saved | {last_fetch_time:%Y-%m-%d %H:%M:%S}")
    return inserted

def purge_old_articles():
    """Delete articles older than DATA_RETENTION_DAYS (30 days)."""
    cutoff = (datetime.now() - timedelta(days=DATA_RETENTION_DAYS)).strftime("%Y-%m-%d")
    try:
        conn = get_db()
        try:
            if USE_MSSQL:
                cur = conn.cursor()
                cur.execute("DELETE FROM articles WHERE pub_date_ist < ?", (cutoff,))
                deleted = cur.rowcount
            else:
                cur = conn.execute("DELETE FROM articles WHERE pub_date_ist < ?", (cutoff,))
                deleted = cur.rowcount
            conn.commit()
            if deleted > 0:
                _log.info(f"[Purge] Deleted {deleted} articles older than {cutoff}")
        finally:
            conn.close()
    except Exception as e:
        _log.error(f"[Purge] {e}")

def auto_fetch_loop():
    fetch_count = 0
    while True:
        try:
            fetch_all_feeds()
            fetch_count += 1
            # Purge articles older than 30 days every 24 fetches (~6h)
            if fetch_count % 24 == 0:
                purge_old_articles()
        except Exception as e:
            print(f"[AutoFetch] {e}")
        elapsed = 0
        while elapsed < FETCH_INTERVAL:
            time.sleep(10); elapsed += 10

# ══════════════════════════════════════════════════════════════════════════════
# LANGUAGE DETECTION & TRANSLATION (no extra deps — Unicode + Google free API)
# ══════════════════════════════════════════════════════════════════════════════
_LANG_NAMES = {
    'hi': 'Hindi', 'ta': 'Tamil', 'te': 'Telugu', 'kn': 'Kannada',
    'ml': 'Malayalam', 'bn': 'Bengali', 'pa': 'Punjabi', 'gu': 'Gujarati',
    'or': 'Odia', 'ur': 'Urdu', 'mr': 'Marathi', 'si': 'Sinhala',
}

def detect_language_unicode(text):
    """Detect language using Unicode block ranges. Returns (lang_code, lang_name)."""
    if not text or len(text) < 20:
        return 'en', 'English'
    counts = {}
    for ch in text:
        o = ord(ch)
        if   0x0900 <= o <= 0x097F: counts['hi'] = counts.get('hi',0)+1
        elif 0x0B80 <= o <= 0x0BFF: counts['ta'] = counts.get('ta',0)+1
        elif 0x0C00 <= o <= 0x0C7F: counts['te'] = counts.get('te',0)+1
        elif 0x0C80 <= o <= 0x0CFF: counts['kn'] = counts.get('kn',0)+1
        elif 0x0D00 <= o <= 0x0D7F: counts['ml'] = counts.get('ml',0)+1
        elif 0x0980 <= o <= 0x09FF: counts['bn'] = counts.get('bn',0)+1
        elif 0x0A00 <= o <= 0x0A7F: counts['pa'] = counts.get('pa',0)+1
        elif 0x0A80 <= o <= 0x0AFF: counts['gu'] = counts.get('gu',0)+1
        elif 0x0B00 <= o <= 0x0B7F: counts['or'] = counts.get('or',0)+1
        elif 0x0600 <= o <= 0x06FF: counts['ur'] = counts.get('ur',0)+1
        elif 0x0D80 <= o <= 0x0DFF: counts['si'] = counts.get('si',0)+1
    if not counts:
        return 'en', 'English'
    best = max(counts, key=counts.get)
    if counts[best] / max(len(text), 1) < 0.05:
        return 'en', 'English'
    return best, _LANG_NAMES.get(best, best.upper())

def google_translate_free(text, src_lang, timeout=15):
    """Translate text→English via Google Translate free endpoint (no API key needed).
    Uses POST body to avoid 400 errors from long/special-char URLs."""
    if not text or src_lang == 'en':
        return text, False
    import urllib.request as _ur, urllib.parse as _up, json as _j
    # Clean text: strip excess whitespace, limit total length
    text = ' '.join(text.split())
    # Split into safe chunks — 1500 chars to stay well under URL/body limits
    chunks = [text[i:i+1500] for i in range(0, min(len(text), 9000), 1500)]
    translated_parts = []
    for chunk in chunks:
        if not chunk.strip():
            continue
        # Use POST with form-encoded body — avoids 400 from long GET URLs
        body = _up.urlencode({
            'client': 'gtx', 'sl': src_lang, 'tl': 'en', 'dt': 't', 'q': chunk
        }).encode('utf-8')
        req_url = 'https://translate.googleapis.com/translate_a/single'
        try:
            req = _ur.Request(req_url, data=body, headers={
                'User-Agent':   'Mozilla/5.0 (Windows NT 10.0; Win64; x64)',
                'Content-Type': 'application/x-www-form-urlencoded',
                'Accept':       '*/*',
            })
            with _ur.urlopen(req, timeout=timeout) as r:
                data = _j.loads(r.read().decode('utf-8'))
                part = ''.join(seg[0] for seg in data[0] if seg and seg[0])
                if part.strip():
                    translated_parts.append(part.strip())
        except Exception as _te:
            _log.warning(f"[Translate] chunk error ({src_lang}): {_te}")
            # Don't abort — try remaining chunks
            continue
    if not translated_parts:
        return text, False
    return ' '.join(translated_parts), True

# ══════════════════════════════════════════════════════════════════════════════
# AI VERIFICATION
# ══════════════════════════════════════════════════════════════════════════════
def verify_heuristic(title, desc):
    """Enhanced heuristic — lowers threshold so fewer Unverified results.
    Checks 15+ fake signals and 20+ credibility signals."""
    text = (title + ' ' + desc).lower()

    # ── Fake / clickbait signals ──────────────────────────────────────────────
    fake_pats = [
        r'you wont believe', r'you won.t believe', r'shocking secret',
        r'illuminati', r'click here', r'share before deleted',
        r'going viral', r'must watch', r'this will shock',
        r'secret revealed', r'conspiracy', r'cover.?up',
        r'deep state', r'wake up', r'100% proof', r'miraculous cure',
    ]
    # ── Credibility / journalistic signals ───────────────────────────────────
    cred_pats = [
        r'said', r'according to', r'minister', r'official',
        r'crore', r'data', r'announced', r'report',
        r'government', r'authorities', r'statement',
        r'press release', r'spokesperson', r'committee',
        r'parliament', r'court', r'police', r'survey',
        r'research', r'study', r'university', r'hospital',
        r'who', r'sebi', r'rbi', r'ngo',
    ]
    fs = sum(1 for p in fake_pats if re.search(p, text))
    cs = sum(1 for p in cred_pats if re.search(p, text))
    title_cred = sum(1 for p in cred_pats if re.search(p, (title or '').lower()))

    if fs >= 2:
        return "❌ Likely Fake", f"{fs} fake/clickbait markers detected"
    if fs == 1 and cs == 0:
        return "⚠️ Unverified", "Clickbait signal — verify manually"
    if cs >= 3 or title_cred >= 2:
        return "✅ Likely Real (75%)", f"{cs} credibility signals — confirmed news language"
    if cs >= 1:
        return "✅ Likely Real (60%)", f"{cs} credibility signal — appears to be news"
    return "⚠️ Unverified (50%)", "Neutral — no strong indicators"

def verify_groq(title, desc, key):
    if not REQUESTS_OK: return None, ""
    try:
        prompt = f'Analyze this news. Reply ONLY with JSON: {{"verdict":"Real"/"Fake"/"Unverified","confidence":0-100,"reason":"1 sentence"}}\nTitle: {title}\nDesc: {desc}'
        r = req_lib.post("https://api.groq.com/openai/v1/chat/completions",
            headers={"Authorization": f"Bearer {key}", "Content-Type": "application/json"},
            json={"model": "llama3-8b-8192", "messages": [{"role": "user", "content": prompt}],
                  "max_tokens": 120, "temperature": 0.1}, timeout=10)
        d = r.json()
        ct = re.sub(r'```json|```', '', d['choices'][0]['message']['content'].strip()).strip()
        res = json.loads(ct)
        v = res.get('verdict', 'Unverified')
        em = "✅" if v == "Real" else "❌" if v == "Fake" else "⚠️"
        return f"{em} {v} ({res.get('confidence', 50)}%)", res.get('reason', '')
    except: return None, ""

def verify_article(aid, force=False):
    try:
        conn = get_db()
        if USE_MSSQL:
            cur = conn.cursor(); cur.execute("SELECT * FROM articles WHERE id=?", (aid,))
            cols = [d[0] for d in cur.description]; row_raw = cur.fetchone()
            row = dict(zip(cols, row_raw)) if row_raw else None
            gk_cur = conn.cursor(); gk_cur.execute("SELECT svalue FROM settings WHERE skey='groq_api_key'")
            gk_raw = gk_cur.fetchone(); gk_val = gk_raw[0] if gk_raw else None
        else:
            row = conn.execute("SELECT * FROM articles WHERE id=?", (aid,)).fetchone()
            gk = conn.execute("SELECT svalue FROM settings WHERE skey='groq_api_key'").fetchone()
            gk_val = gk[0] if gk and gk[0] else None
        if not row: conn.close(); return
        if not force and (row['ai_verified'] if isinstance(row, dict) else row['ai_verified']) != 'pending':
            conn.close(); return
        title = row['title'] if isinstance(row, dict) else row['title']
        desc  = (row['description'] or '') if isinstance(row, dict) else (row['description'] or '')
        conn.close()
    except Exception as e:
        print(f"[Verify] Read error: {e}"); return

    # ── Detect language; translate if regional so Groq/heuristic works well ──
    lang_prefix = ""
    detected_lang, lang_name = detect_language_unicode((title or '') + ' ' + (desc or ''))
    if detected_lang != 'en':
        _log.info(f"[Verify] Detected {lang_name} for article {aid} — translating before verify")
        t_title, ok1 = google_translate_free(title, detected_lang)
        t_desc,  ok2 = google_translate_free(desc,  detected_lang)
        if ok1 or ok2:
            if ok1: title = t_title
            if ok2: desc  = t_desc
            lang_prefix = f"[{lang_name}→EN] "
        else:
            lang_prefix = f"[{lang_name}] "

    verdict, reason = None, ""
    if gk_val: verdict, reason = verify_groq(title, desc, gk_val)
    if not verdict: verdict, reason = verify_heuristic(title, desc)

    # ── Source trust level adjustment ────────────────────────────────────────
    # Boost confidence for high-trust sources, reduce for low-trust ones
    source_name = row['source'] if isinstance(row, dict) else row['source']
    trust = _get_source_trust(source_name)
    if verdict and trust >= 80:
        # High-trust source: upgrade Unverified → Real if no red flags
        if verdict.startswith('⚠️'):
            verdict = '✅ Real (80%)'
            reason = f'[Trust:{trust}] High-credibility source ({source_name}). ' + (reason or '')
        elif verdict.startswith('✅'):
            # Bump confidence if already Real
            import re as _re_v
            m = _re_v.search(r'(\d+)%', verdict)
            if m:
                conf = min(int(m.group(1)) + 10, 99)
                verdict = _re_v.sub(r'\d+%', f'{conf}%', verdict)
            reason = f'[Trust:{trust}] ' + (reason or '')
    elif verdict and trust <= 35:
        # Low-trust source: downgrade Real → Unverified
        if verdict.startswith('✅'):
            verdict = '⚠️ Unverified (45%)'
            reason = f'[Trust:{trust}] Low-trust source ({source_name}) — treat with caution. ' + (reason or '')
        reason = f'[Trust:{trust}] ' + (reason or '')

    # Prepend language tag to reason so users know translation was applied
    if lang_prefix:
        reason = lang_prefix + (reason or '')

    with _db_lock:
        try:
            conn = get_db()
            if USE_MSSQL:
                conn.cursor().execute("UPDATE articles SET ai_verified=?,ai_verdict=? WHERE id=?", (verdict, reason, aid))
            else:
                conn.execute("UPDATE articles SET ai_verified=?,ai_verdict=? WHERE id=?", (verdict, reason, aid))
            conn.commit()
        except Exception as e: print(f"[Verify] Write error: {e}")
        finally: conn.close()

def batch_verify(ids, force=False):
    """Run verification in parallel threads for speed — up to 16 threads."""
    if not ids: return
    from concurrent.futures import ThreadPoolExecutor
    def single(aid):
        try: verify_article(aid, force)
        except Exception as e: print(f"[BatchVerify] {e}")
    # Use thread pool for fast parallel verification
    max_workers = min(16, len(ids))
    with ThreadPoolExecutor(max_workers=max_workers) as ex:
        futures = [ex.submit(single, aid) for aid in ids]
        # Don't block — fire and forget in background
    print(f"[Verify] Dispatched {len(ids)} articles to {max_workers} threads")

# ══════════════════════════════════════════════════════════════════════════════
# MAP DATA
# ══════════════════════════════════════════════════════════════════════════════
def get_map_data(topic_filter=None):
    conn = get_db()
    try:
        if USE_MSSQL:
            cur = conn.cursor()
            cur.execute("SELECT cities, category, priority, topics FROM articles WHERE cities IS NOT NULL")
            rows = [{"cities": r[0], "category": r[1], "priority": r[2], "topics": r[3]} for r in cur.fetchall()]
        else:
            rows = conn.execute("SELECT cities, category, priority, topics FROM articles WHERE cities IS NOT NULL").fetchall()
    finally:
        conn.close()
    cc = defaultdict(lambda: {"count": 0, "category": "Other", "priority": "Low"})
    for r in rows:
        try:
            raw_cities = r['cities'] if isinstance(r, dict) else r['cities']
            raw_topics = r['topics'] if isinstance(r, dict) else r['topics']
            cats = json.loads(raw_cities or '[]')
            if not cats: cats = ['india']
            # topic filter
            if topic_filter:
                art_topics = json.loads(raw_topics or '[]')
                if topic_filter not in art_topics: continue
            cat = r['category'] if isinstance(r, dict) else r['category']
            pri = r['priority'] if isinstance(r, dict) else r['priority']
            for c in cats:
                c = c.lower()
                cc[c]["count"] += 1
                if pri == "High" or cc[c]["priority"] != "High":
                    cc[c]["category"] = cat or "Other"
                    cc[c]["priority"] = pri or "Low"
        except: pass
    result = []
    for c, v in cc.items():
        if c == 'india':
            result.append({"city":"India (General)","count":v["count"],"lat":22.0,"lng":78.0,
                           "category":v["category"],"priority":v["priority"]})
        elif c.startswith('state:'):
            sn = c[6:]
            if sn in INDIA_STATES:
                result.append({"city":sn.title()+" (State)","count":v["count"],
                               "lat":INDIA_STATES[sn][0],"lng":INDIA_STATES[sn][1],
                               "category":v["category"],"priority":v["priority"]})
        elif c in INDIA_CITIES:
            result.append({"city":c.title(),"count":v["count"],
                           "lat":INDIA_CITIES[c][0],"lng":INDIA_CITIES[c][1],
                           "category":v["category"],"priority":v["priority"]})
    return result

