def make_csv(rows, logo_b64=None):
    output = io.StringIO()
    writer = csv.writer(output)
    writer.writerow(["JCF RSS News Dashboard"])
    writer.writerow([f"Generated: {now_ist()} | Total: {len(rows)} articles"])
    writer.writerow([])
    writer.writerow(["#", "Source", "Title", "Link", "Date (IST)", "City", "Category", "Priority",
                     "Sentiment", "Topics", "AI Verdict", "Read"])
    for i, r in enumerate(rows, 1):
        cities = r.get('cities', [])
        city_str = ', '.join(c.title() for c in cities if c != 'india') if any(c != 'india' for c in cities) else 'India'
        writer.writerow([i, r.get('source',''), r.get('title',''), r.get('link',''),
                         r.get('pub_date_ist',''), city_str, r.get('category',''), r.get('priority',''),
                         r.get('sentiment',''), ','.join(r.get('topics',[])),
                         r.get('ai_verified',''), 'Yes' if r.get('is_read') else 'No'])
    output.seek(0)
    return output.getvalue().encode('utf-8-sig')


def get_export_logo():
    """Get logo base64 for export files - tries disk path first, then DB."""
    # Try fixed logo path
    try:
        if os.path.isfile(LOGO_PATH):
            with open(LOGO_PATH, 'rb') as f:
                raw = f.read()
            encoded = base64.b64encode(raw).decode()
            mime = 'image/jpeg' if LOGO_PATH.lower().endswith(('.jpg','.jpeg')) else 'image/png'
            return f"data:{mime};base64,{encoded}"
    except: pass
    # Fallback: DB logo_data
    try:
        conn = get_db()
        if USE_MSSQL:
            cur = conn.cursor()
            cur.execute("SELECT svalue FROM settings WHERE skey='logo_data'")
            row = cur.fetchone(); val = row[0] if row else None
        else:
            row = conn.execute("SELECT svalue FROM settings WHERE skey='logo_data'").fetchone()
            val = row[0] if row else None
        conn.close()
        return val
    except: return None

def _pdf_cell(pdf, w, h, txt, border=0, ln=0, fill=False, align=''):
    """Wrapper that works with both fpdf1 (ln= param) and fpdf2 (new_x/new_y)."""
    try:
        if _fpdf2:
            from fpdf.enums import XPos, YPos
            nx = XPos.LMARGIN if ln else XPos.RIGHT
            ny = YPos.NEXT if ln else YPos.TOP
            pdf.cell(w, h, txt, border=border, fill=fill, align=align, new_x=nx, new_y=ny)
        else:
            pdf.cell(w, h, txt, border=border, ln=ln, fill=fill, align=align)
    except Exception:
        # Ultimate fallback
        try:
            pdf.cell(w, h, txt, border=border, ln=ln, fill=fill)
        except Exception:
            pdf.cell(w, h, txt)

def _logo_to_tmpfile(logo_b64):
    """Decode base64 logo to a temp file. Returns path or None."""
    if not logo_b64:
        return None
    try:
        import tempfile as _lt
        raw = base64.b64decode(logo_b64.split(',', 1)[-1])
        suffix = '.png' if 'png' in logo_b64[:30] else '.jpg'
        tf = _lt.NamedTemporaryFile(suffix=suffix, delete=False)
        tf.write(raw); tf.flush(); tf.close()
        return tf.name
    except Exception as _le:
        print(f"[PDF] logo decode error: {_le}")
        return None


def make_pdf_simple(rows, title_text="JCF News Report", logo_b64=None, include_read_by=False, read_by_name="", section=""):
    """Landscape A4 PDF — columns match dashboard:
    # | Pri | Cat | Source | Title | City | Time(IST) | Sentiment | Topics
    Header: JCF logo centred.
    Report title centred below header rule on every page.
    """
    if not PDF_OK:
        raise RuntimeError("fpdf library not installed. Run: pip install fpdf2 --break-system-packages")

    jcf_tmp = _logo_to_tmpfile(logo_b64)

    try:
        def _safe(s, n=200):
            s = (str(s) or '')[:n]
            s = (s.replace('—', '-').replace('–', '-')
                  .replace('’', "'").replace('‘', "'")
                  .replace('“', '"').replace('”', '"')
                  .replace('…', '...').replace(' ', ' ')
                  .replace('₹', 'Rs').replace('·', '-'))
            return s.encode('latin-1', errors='replace').decode('latin-1')

        _title_safe = _safe(title_text, 80)
        _meta_safe  = _safe(f"Generated: {now_ist()}  |  Total: {len(rows)} articles", 120)

        class JCFPDF(FPDF):
            def header(self):
                # LEFT: JCF brand text in orange
                self.set_xy(10, 6)
                self.set_font("Helvetica", "B", 16)
                self.set_text_color(249, 115, 22)
                self.cell(50, 9, "JCF", ln=False)
                # CENTRE: report name in dark blue
                self.set_xy(60, 7)
                self.set_font("Helvetica", "B", 12)
                self.set_text_color(30, 58, 95)
                self.cell(167, 8, _title_safe, align='C', ln=False)
                # RIGHT: JCF logo image
                if jcf_tmp:
                    try:
                        self.image(jcf_tmp, x=248, y=3, h=16)
                    except Exception as _he:
                        print(f"[PDF] header logo error: {_he}")
                # Orange separator line
                self.set_draw_color(249, 115, 22)
                self.set_line_width(0.5)
                self.line(10, 23, 287, 23)
                # Meta line centred below separator
                self.set_xy(10, 25)
                self.set_font("Helvetica", "", 7)
                self.set_text_color(120, 120, 120)
                self.cell(0, 5, _meta_safe, align='C', ln=True)
                self.ln(1)

            def footer(self):
                # Page number bottom-left
                self.set_y(-12)
                self.set_font("Helvetica", "I", 7)
                self.set_text_color(150, 150, 150)
                self.cell(0, 5, f"Page {self.page_no()}", align='L')

        pdf = JCFPDF(orientation='L')
        pdf.set_auto_page_break(auto=True, margin=20)
        pdf.add_page()

        # ── Columns matching dashboard exactly ───────────────────────────────
        # #(7) | Pri(18) | Cat(30) | Source(28) | Title(82) | City(28) | Time(22) | Sentiment(22) | Topics(28) | total≈265
        if include_read_by:
            col_w      = [7, 18, 30, 28, 72, 28, 22, 22, 28, 28]
            col_labels = ["#","Pri","Cat","Source","Title","City","Time(IST)","Sentiment","Topics","Read By"]
        else:
            col_w      = [7,  18,  30,  28,  82,  28,  22,  22,  28]
            col_labels = ["#","Pri","Cat","Source","Title","City","Time(IST)","Sentiment","Topics"]

        pdf.set_fill_color(30, 58, 95)
        pdf.set_text_color(255, 255, 255)
        pdf.set_font("Helvetica", "B", 7)
        for j, (w, lbl) in enumerate(zip(col_w, col_labels)):
            _pdf_cell(pdf, w, 7, lbl, border=1, fill=True, ln=(j == len(col_w) - 1))

        # ── Data rows ─────────────────────────────────────────────────────────
        pri_colors = {"High": (239, 68, 68), "Medium": (245, 158, 11), "Low": (34, 197, 94)}
        sent_marks = {"positive": "pos", "negative": "neg", "neutral": "neu"}

        def _c(s, n):
            s = (str(s) or '')[:n]
            s = (s.replace('—', '-').replace('–', '-')
                  .replace('’', "'").replace('‘', "'")
                  .replace('“', '"').replace('”', '"')
                  .replace('…', '...').replace(' ', ' ')
                  .replace('₹', 'Rs').replace('·', '-'))
            return s.encode('latin-1', errors='replace').decode('latin-1')

        for i, r in enumerate(rows[:500], 1):
            cities   = r.get('cities', [])
            city_str = (', '.join(c.title() for c in cities
                            if c != 'india' and not c.startswith('state:'))
                        or ', '.join(c[6:].title() for c in cities if c.startswith('state:'))
                        or 'India')[:22]
            pri  = r.get('priority', 'Low')
            sent = r.get('sentiment', 'neutral')
            tstr = (r.get('pub_date_ist') or '')
            tstr = tstr[11:16] if len(tstr) > 11 else tstr
            topics_str = ', '.join(r.get('topics') or [])[:22]
            rc   = pri_colors.get(pri, (200, 200, 200))

            pdf.set_fill_color(245, 245, 245) if i % 2 == 0 else pdf.set_fill_color(255, 255, 255)
            sent_sym = {'positive': '+', 'negative': '-', 'neutral': 'o'}.get(sent, 'o')
            row_data = [
                str(i),
                _c(pri, 8),
                _c(r.get('category', ''), 18),
                _c(r.get('source',   ''), 22),
                _c(r.get('title',    ''), 75),
                _c(city_str,              22),
                _c(tstr,                  10),
                sent_sym + ' ' + _c(sent, 8),
                _c(topics_str,            22),
            ]
            if include_read_by:
                _is_read_sec = section in ('readnews', 'readtoday', 'readtopics')
                _rb_val = read_by_name if (_is_read_sec or bool(r.get('is_read'))) else ''
                row_data.append(_c(_rb_val, 25))
            for j, (w, val) in enumerate(zip(col_w, row_data)):
                if j == 1:   # Pri col — colour coded
                    pdf.set_text_color(*rc)
                elif j == 7:  # Sentiment col
                    sc = (34,197,94) if sent=='positive' else (239,68,68) if sent=='negative' else (100,100,100)
                    pdf.set_text_color(*sc)
                elif include_read_by and j == 9:  # Read By col
                    pdf.set_text_color(6, 182, 212)  # cyan
                else:
                    pdf.set_text_color(0, 0, 0)
                _pdf_cell(pdf, w, 6, val, border=1, fill=True, ln=(j == len(col_w) - 1))

        # ── Output ────────────────────────────────────────────────────────────
        try:
            out = pdf.output()
        except TypeError:
            out = pdf.output(dest='S')
        if isinstance(out, str):
            out = out.encode('latin-1')
        elif isinstance(out, bytearray):
            out = bytes(out)
        if not isinstance(out, bytes) or len(out) < 100:
            raise ValueError(f"PDF output invalid: type={type(out)} len={len(out) if out else 0}")
        print(f"[PDF] Generated OK — {len(out)} bytes, {len(rows)} rows")
        return out, 'application/pdf'

    except Exception as e:
        print(f"[PDF] generation error ({type(e).__name__}): {e}")
        import traceback; traceback.print_exc()
        raise

    finally:
        for _tmp in [jcf_tmp]:
            try:
                if _tmp and os.path.exists(_tmp):
                    os.unlink(_tmp)
            except Exception:
                pass

def make_pdf_topics(top20_rows, title_text="JCF - Top 20 Topics Report", logo_b64=None, read_by_name=""):
    """Landscape A4 PDF for Top 20 Topics with Read By column."""
    if not PDF_OK:
        raise RuntimeError("fpdf library not installed. Run: pip install fpdf2 --break-system-packages")

    jcf_tmp = _logo_to_tmpfile(logo_b64)

    try:
        def _safe(s, n=200):
            s = (str(s) or '')[:n]
            s = (s.replace('\u2014', '-').replace('\u2013', '-')
                  .replace('\u2018', "'").replace('\u2019', "'")
                  .replace('\u201c', '"').replace('\u201d', '"')
                  .replace('\u2026', '...').replace('\u00a0', ' ')
                  .replace('\u20b9', 'Rs').replace('\u00b7', '-'))
            return s.encode('latin-1', errors='replace').decode('latin-1')

        _title_safe = _safe(title_text, 80)
        _meta_safe  = _safe(f"Generated: {now_ist()}  |  Topics: {len(top20_rows)}", 120)

        class TopicsPDF(FPDF):
            def header(self):
                self.set_xy(10, 6)
                self.set_font("Helvetica", "B", 16)
                self.set_text_color(249, 115, 22)
                self.cell(50, 9, "JCF", ln=False)
                self.set_xy(60, 7)
                self.set_font("Helvetica", "B", 12)
                self.set_text_color(30, 58, 95)
                self.cell(167, 8, _title_safe, align='C', ln=False)
                if jcf_tmp:
                    try: self.image(jcf_tmp, x=248, y=3, h=16)
                    except Exception as _he: print(f"[PDF] header logo error: {_he}")
                self.set_draw_color(249, 115, 22)
                self.set_line_width(0.5)
                self.line(10, 23, 287, 23)
                self.set_xy(10, 25)
                self.set_font("Helvetica", "", 7)
                self.set_text_color(120, 120, 120)
                self.cell(0, 5, _meta_safe, align='C', ln=True)
                self.ln(1)

            def footer(self):
                self.set_y(-12)
                self.set_font("Helvetica", "I", 7)
                self.set_text_color(150, 150, 150)
                self.cell(0, 5, f"Page {self.page_no()}", align='L')

        pdf = TopicsPDF(orientation='L')
        pdf.set_auto_page_break(auto=True, margin=20)
        pdf.add_page()

        # Columns: # | Topic | Total | Read | Unread | Sentiment | Read By
        col_w      = [7, 80, 22, 22, 22, 30, 40]
        col_labels = ["#", "Topic", "Total", "Read", "Unread", "Sentiment", "Read By"]

        pdf.set_fill_color(30, 58, 95)
        pdf.set_text_color(255, 255, 255)
        pdf.set_font("Helvetica", "B", 7)
        for j, (w, lbl) in enumerate(zip(col_w, col_labels)):
            _pdf_cell(pdf, w, 7, lbl, border=1, fill=True, ln=(j == len(col_w) - 1))

        for i, t in enumerate(top20_rows, 1):
            topic = _safe(t.get('topic', ''), 60)
            total = str(t.get('count', 0))
            read  = str(t.get('read', 0))
            unread = str(t.get('unread', 0))
            dom = 'positive' if t.get('positive',0) > t.get('negative',0) else ('negative' if t.get('negative',0) > t.get('positive',0) else 'neutral')
            sent_disp = dom.capitalize()
            rb = _safe(read_by_name, 30) if t.get('read', 0) > 0 else ''

            pdf.set_fill_color(245, 245, 245) if i % 2 == 0 else pdf.set_fill_color(255, 255, 255)
            row_data = [str(i), topic, total, read, unread, sent_disp, rb]
            for j, (w, val) in enumerate(zip(col_w, row_data)):
                if j == 3:  # Read count — green
                    pdf.set_text_color(34, 197, 94)
                elif j == 4:  # Unread — red
                    pdf.set_text_color(239, 68, 68)
                elif j == 5:  # Sentiment
                    sc = (34,197,94) if dom=='positive' else (239,68,68) if dom=='negative' else (100,100,100)
                    pdf.set_text_color(*sc)
                elif j == 6:  # Read By — cyan
                    pdf.set_text_color(6, 182, 212)
                else:
                    pdf.set_text_color(0, 0, 0)
                _pdf_cell(pdf, w, 6, val, border=1, fill=True, ln=(j == len(col_w) - 1))

        try:
            out = pdf.output()
        except TypeError:
            out = pdf.output(dest='S')
        if isinstance(out, str):
            out = out.encode('latin-1')
        elif isinstance(out, bytearray):
            out = bytes(out)
        if not isinstance(out, bytes) or len(out) < 100:
            raise ValueError(f"PDF output invalid: type={type(out)} len={len(out) if out else 0}")
        print(f"[PDF Topics] Generated OK — {len(out)} bytes, {len(top20_rows)} topics")
        return out, 'application/pdf'

    except Exception as e:
        print(f"[PDF Topics] generation error ({type(e).__name__}): {e}")
        import traceback; traceback.print_exc()
        raise

    finally:
        for _tmp in [jcf_tmp]:
            try:
                if _tmp and os.path.exists(_tmp):
                    os.unlink(_tmp)
            except Exception:
                pass

def make_excel(rows_all, rows_today, top20, pivot_all, pivot_today, logo_b64=None, pivot_topics=None, rows_alerts=None):
    """Excel workbook. Banner rows 1-3 written first, col header row 4, data row 5+.
    No insert_rows — prevents openpyxl column-reference corruption.
    User management and device logs are NOT included — visible only in their dedicated dashboard sections."""
    from openpyxl.utils import get_column_letter
    wb = openpyxl.Workbook()

    def _banner(ws, ncols):
        lc = get_column_letter(max(ncols, 1))
        try: ws.merge_cells(f'A1:{lc}3')
        except Exception: pass
        cell = ws['A1']
        cell.value = f"JCF — {ws.title}"
        cell.font  = Font(bold=True, size=14, color="F97316")
        cell.fill  = PatternFill("solid", fgColor="0a0f1e")
        cell.alignment = Alignment(horizontal="center", vertical="center")
        ws.row_dimensions[1].height = 38
        ws.row_dimensions[2].height = 4
        ws.row_dimensions[3].height = 4
        # Logo intentionally excluded from Excel to prevent export errors

    def _col_hdr(ws, cols, color="1e3a5f"):
        for j, h in enumerate(cols, 1):
            cl = ws.cell(4, j, h)
            cl.fill = PatternFill("solid", fgColor=color)
            cl.font = Font(bold=True, color="FFFFFF", size=10)
            cl.alignment = Alignment(horizontal="center", wrap_text=True)
        ws.row_dimensions[4].height = 24

    def _row_bg(ws, rn, sent):
        fg = {"positive": "E8F5E9", "negative": "FFEBEE", "neutral": "F5F5F5"}.get(sent, "F5F5F5")
        for j in range(1, ws.max_column + 1):
            ws.cell(rn, j).fill = PatternFill("solid", fgColor=fg)

    def _auto_w(ws):
        for col in ws.iter_cols():
            try:
                w = max((len(str(c.value or "")) for c in col), default=8)
                ws.column_dimensions[col[0].column_letter].width = min(max(w + 2, 10), 60)
            except Exception: pass

    ACOLS = ["#","Source","Title","Link","Date(IST)","City","Category","Priority","Sentiment","AI Verdict","Read"]

    def _city(r):
        cities = r.get('cities', [])
        return ', '.join(x.title() for x in cities if x != 'india') if any(x != 'india' for x in cities) else 'India'

    def _write_arts(ws, rows, hdr_color):
        _banner(ws, len(ACOLS))
        _col_hdr(ws, ACOLS, hdr_color)
        for i, r in enumerate(rows, 1):
            rn = i + 4
            d = [i, r.get('source',''), r.get('title',''), r.get('link',''), r.get('pub_date_ist',''),
                 _city(r), r.get('category',''), r.get('priority',''), r.get('sentiment',''),
                 r.get('ai_verified',''), 'Yes' if r.get('is_read') else 'No']
            for j, v in enumerate(d, 1):
                cl = ws.cell(rn, j, v)
                if j == 4 and v:
                    try: cl.hyperlink = v
                    except Exception: pass
                    cl.font = Font(color="0563C1", underline="single")
            _row_bg(ws, rn, r.get('sentiment', ''))
        _auto_w(ws)

    # Sheet 1: All Articles
    ws1 = wb.active; ws1.title = "All Articles"
    _write_arts(ws1, rows_all, "1e3a5f")

    # Sheet 2: Today
    ws2 = wb.create_sheet("Today")
    _write_arts(ws2, rows_today, "1a6b3c")

    # Sheet 3: Read All Articles
    ws_ra = wb.create_sheet("Read All Articles")
    _write_arts(ws_ra, [r for r in rows_all if r.get('is_read')], "1a4b6b")

    # Sheet 4: Read Today News
    ws_rt = wb.create_sheet("Read Today News")
    _write_arts(ws_rt, [r for r in rows_today if r.get('is_read')], "1a5c3a")

    # Sheet 5: Read Topic News (today, read, has topics)
    ws_rtn = wb.create_sheet("Read Topic News")
    _write_arts(ws_rtn, [r for r in rows_today if r.get('is_read') and r.get('topics')], "3b1a6b")

    # Sheet 6: Top 20 Topics
    ws3 = wb.create_sheet("Top 20 Topics")
    T20 = ["#","Topic","Total","Read","Unread"]
    _banner(ws3, len(T20)); _col_hdr(ws3, T20, "6b1a6b")
    for i, t in enumerate(top20, 1):
        for j, v in enumerate([i, t['topic'], t['count'], t['read'], t['unread']], 1):
            ws3.cell(i + 4, j, v)
    _auto_w(ws3)

    # Sheet 7: Read Top-20 Topics (topics where read > 0)
    ws_r20 = wb.create_sheet("Read Top-20 Topics")
    rt20 = [t for t in top20 if t.get('read', 0) > 0]
    _banner(ws_r20, len(T20)); _col_hdr(ws_r20, T20, "1a4f6b")
    for i, t in enumerate(rt20, 1):
        for j, v in enumerate([i, t['topic'], t['count'], t['read'], t['unread']], 1):
            ws_r20.cell(i + 4, j, v)
    _auto_w(ws_r20)

    # Sheets 8–9: Pivot All / Today
    PVCOLS = ["Source","Total","Positive","Negative","Neutral","Read","Unread"]
    for ws_p, rows_p, color in [
        (wb.create_sheet("Pivot All"),   pivot_all,   "b45309"),
        (wb.create_sheet("Pivot Today"), pivot_today, "047857"),
    ]:
        _banner(ws_p, len(PVCOLS)); _col_hdr(ws_p, PVCOLS, color)
        for i, r in enumerate(rows_p, 1):
            for j, v in enumerate([r['source'], r['total'], r['positive'], r['negative'], r['neutral'], r['read'], r['unread']], 1):
                ws_p.cell(i + 4, j, v)
        _auto_w(ws_p)

    # Sheets 10–11: Topics Pivot
    if pivot_topics:
        TPCOLS = ["#","Topic","Total","Read","Unread","Positive","Negative","Neutral"]
        for sname, key, color in [("Topics Pivot All","all","4c1d95"),("Topics Pivot Today","today","7c3aed")]:
            wt = wb.create_sheet(sname)
            _banner(wt, len(TPCOLS)); _col_hdr(wt, TPCOLS, color)
            for i, t in enumerate(pivot_topics.get(key, []), 1):
                for j, v in enumerate([i, t['topic'], t['count'], t['read'], t['unread'],
                                        t.get('positive',0), t.get('negative',0), t.get('neutral',0)], 1):
                    wt.cell(i + 4, j, v)
            _auto_w(wt)

    # Sheet 12: Today News on Topic
    ws_tnt = wb.create_sheet("Today News on Topic")
    TNTCOLS = ["#","Source","Title","Link","Date(IST)","City","Category","Priority","Sentiment","Topics","AI Verdict","Read"]
    _banner(ws_tnt, len(TNTCOLS)); _col_hdr(ws_tnt, TNTCOLS, "1a3d6b")
    for i, r in enumerate([r for r in rows_today if r.get('topics')], 1):
        rn = i + 4
        d = [i, r.get('source',''), r.get('title',''), r.get('link',''), r.get('pub_date_ist',''),
             _city(r), r.get('category',''), r.get('priority',''), r.get('sentiment',''),
             ', '.join(r.get('topics',[])), r.get('ai_verified',''), 'Yes' if r.get('is_read') else 'No']
        for j, v in enumerate(d, 1):
            cl = ws_tnt.cell(rn, j, v)
            if j == 4 and v:
                try: cl.hyperlink = v
                except Exception: pass
                cl.font = Font(color="0563C1", underline="single")
        _row_bg(ws_tnt, rn, r.get('sentiment', ''))
    _auto_w(ws_tnt)

    # Sheet 13: Alerts (High Priority / Urgent)
    ws_alerts = wb.create_sheet("Alerts")
    ALERTCOLS = ["#","Source","Title","Link","Date(IST)","City","Category","Priority","Sentiment","AI Verdict","Read"]
    _banner(ws_alerts, len(ALERTCOLS)); _col_hdr(ws_alerts, ALERTCOLS, "7f1d1d")
    alerts_rows = rows_alerts if rows_alerts is not None else [r for r in rows_all if r.get('priority')=='High' or r.get('is_urgent')]
    for i, r in enumerate(alerts_rows, 1):
        rn = i + 4
        d = [i, r.get('source',''), r.get('title',''), r.get('link',''), r.get('pub_date_ist',''),
             _city(r), r.get('category',''), r.get('priority',''), r.get('sentiment',''),
             r.get('ai_verified',''), 'Yes' if r.get('is_read') else 'No']
        for j, v in enumerate(d, 1):
            cl = ws_alerts.cell(rn, j, v)
            if j == 4 and v:
                try: cl.hyperlink = v
                except Exception: pass
                cl.font = Font(color="0563C1", underline="single")
        _row_bg(ws_alerts, rn, r.get('sentiment', ''))
    _auto_w(ws_alerts)

    # Sheet 14: Favourites
    ws_fav = wb.create_sheet("Favourites")
    _write_arts(ws_fav, [r for r in rows_all if r.get('_is_fav')], "b45309")

    # Sheet 15: Read Latest Articles
    ws_rl = wb.create_sheet("Read Latest Articles")
    _write_arts(ws_rl, [r for r in rows_all if r.get('is_read')], "1a4b6b")

    # Sheet 16: Read Today News
    ws_rtd = wb.create_sheet("Read Today News")
    _write_arts(ws_rtd, [r for r in rows_today if r.get('is_read')], "1a5c3a")

    # Sheet 17: Read Top-20 Topics (topics with read > 0)
    ws_rt20 = wb.create_sheet("Read Top-20 Topics")
    T20RT = ["#","Topic","Total","Read","Unread"]
    _banner(ws_rt20, len(T20RT)); _col_hdr(ws_rt20, T20RT, "1a4f6b")
    rt20_read = [t for t in top20 if t.get('read', 0) > 0]
    for i, t in enumerate(rt20_read, 1):
        for j, v in enumerate([i, t['topic'], t['count'], t['read'], t['unread']], 1):
            ws_rt20.cell(i + 4, j, v)
    _auto_w(ws_rt20)



    buf = io.BytesIO(); wb.save(buf); buf.seek(0); return buf

# ══════════════════════════════════════════════════════════════════════════════
# HELPERS
# ══════════════════════════════════════════════════════════════════════════════
def rows_to_dicts(rows):
    """Convert pyodbc rows to plain dicts with parsed JSON fields."""
    result = []
    for r in rows:
        d = dict(r) if isinstance(r, dict) else dict(zip(r.keys(), tuple(r)))
        for field in ('cities', 'topics'):
            try: d[field] = json.loads(d.get(field) or '[]')
            except: d[field] = []
        d['is_read'] = bool(d.get('is_read', 0))
        d['is_alert'] = bool(d.get('is_alert', 0))
        d['is_urgent'] = bool(d.get('is_urgent', 0))
        result.append(d)
    return result

