@app.route('/api/reset_admin', methods=['POST'])
def api_reset_admin():
    """Emergency: reset admin password to admin@123. Only works from localhost."""
    if request.remote_addr not in ('127.0.0.1', '::1', 'localhost'):
        return jsonify({"error": "Only accessible from localhost"}), 403
    try:
        conn = get_db()
        try:
            new_hash = hash_pw('admin@123')
            if USE_MSSQL and not _using_sqlite_fallback:
                cur = conn.cursor()
                cur.execute("UPDATE users SET password_hash=?, is_active=1 WHERE username='admin'", (new_hash,))
                if cur.rowcount == 0:
                    cur.execute("INSERT INTO users (username,password_hash,full_name,role,is_active,created_at) VALUES (?,?,?,?,1,?)",
                                ('admin', new_hash, 'Administrator', 'admin', datetime.now().isoformat()))
            else:
                conn.execute("UPDATE users SET password_hash=?, is_active=1 WHERE username='admin'", (new_hash,))
                if conn.execute("SELECT changes()").fetchone()[0] == 0:
                    conn.execute("INSERT INTO users (username,password_hash,full_name,role,is_active,created_at) VALUES (?,?,?,?,1,?)",
                                 ('admin', new_hash, 'Administrator', 'admin', 1, datetime.now().isoformat()))
            conn.commit()
            return jsonify({"ok": True, "message": "Admin password reset to admin@123"})
        finally:
            conn.close()
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})

