@app.route('/api/admin/create_user', methods=['POST'])
def api_create_user():
    u = session.get('user')
    if not u or u['role'].lower() != 'admin': return jsonify({"error": "Forbidden"}), 403
    data = request.json
    username = (data.get('username') or '').strip().lower()
    password = data.get('password') or ''
    full_name = data.get('full_name', '').strip()
    role = data.get('role', 'viewer')
    if not username: return jsonify({"ok": False, "error": "Username required"})
    if len(password) < 6: return jsonify({"ok": False, "error": "Password min 6 chars"})
    if role not in ('viewer', 'editor', 'admin'): role = 'viewer'
    conn = get_db()
    try:
        if USE_MSSQL:
            cur = conn.cursor(); cur.execute("SELECT COUNT(*) FROM users WHERE username != 'icomply'"); count = cur.fetchone()[0]
        else:
            count = conn.execute("SELECT COUNT(*) FROM users WHERE username != 'icomply'").fetchone()[0]
        if count >= 20: return jsonify({"ok": False, "error": "Max 20 users"})
        try:
            if USE_MSSQL:
                conn.cursor().execute("INSERT INTO users (username,password_hash,full_name,role,is_active,created_at) VALUES (?,?,?,?,1,?)",
                                      (username, hash_pw(password), full_name, role, datetime.now().isoformat()))
            else:
                conn.execute("INSERT INTO users (username,password_hash,full_name,role,is_active,created_at) VALUES (?,?,?,?,1,?)",
                             (username, hash_pw(password), full_name, role, datetime.now().isoformat()))
            conn.commit(); return jsonify({"ok": True})
        except Exception as e:
            if 'UNIQUE' in str(e) or 'unique' in str(e) or '2627' in str(e):
                return jsonify({"ok": False, "error": "Username already exists"})
            raise
    finally: conn.close()

