# Auto-detect logo: looks next to the script OR in logo/ subfolder
_SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
# JCF logo embedded as fallback (shown even before file is placed on disk)
_EMBEDDED_LOGO = "data:image/png;base64," + EMBEDDED_LOGO_B64
def _find_logo_path():
    """Auto-detect logo file next to the script or in a logo/ subfolder."""
    _sd = os.path.dirname(os.path.abspath(__file__))
    # Check common locations relative to the script
    candidates = [
        os.path.join(_sd, 'logo', 'JCF.jpg'),
        os.path.join(_sd, 'logo', 'JCF.png'),
        os.path.join(_sd, 'logo', 'logo.jpg'),
        os.path.join(_sd, 'logo', 'logo.png'),
        os.path.join(_sd, 'JCF.jpg'),
        os.path.join(_sd, 'JCF.png'),
        os.path.join(_sd, 'logo.jpg'),
        os.path.join(_sd, 'logo.png'),
        # Windows user paths as last resort
        r"C:\Users\Administrator\Documents\JCF RSS Dashboard\Logo\JCF.jpg",
        r"C:\Users\Administrator\Documents\JCF RSS Dashboard\Logo\JCF.jpg",
    ]
    for p in candidates:
        if os.path.isfile(p):
            return p
    return None

LOGO_PATH = _find_logo_path()

@app.route('/api/get_logo')
def api_get_logo():
    """Load logo: auto-detects from script folder or logo/ subfolder. Falls back to embedded logo."""
    if not session.get('user'): return jsonify({"logo": ""}), 401
    # Try file path (refreshed each request so dropping a new logo.jpg works instantly)
    _dynamic_path = _find_logo_path()
    if _dynamic_path:
        try:
            with open(_dynamic_path, 'rb') as f:
                raw = f.read()
            encoded = base64.b64encode(raw).decode()
            ext = _dynamic_path.lower()
            mime = 'image/jpeg' if ext.endswith(('.jpg','.jpeg')) else 'image/png'
            return jsonify({"logo": f"data:{mime};base64,{encoded}"})
        except Exception as e:
            print(f"[Logo] Path load failed: {e}")
    # Fallback: embedded JCF logo (always available)
    if _EMBEDDED_LOGO:
        return jsonify({"logo": _EMBEDDED_LOGO})
    return jsonify({"logo": ""})

