@app.route('/api/feed_health')
def api_feed_health():
    """Return latest feed health from feed_health_log SQL table."""
    if not session.get('user'): return jsonify([]), 401
    conn = get_db()
    try:
        if USE_MSSQL:
            cur = conn.cursor()
            # Latest row per feed_url
            cur.execute("""
                SELECT feed_name, feed_url, status, failures, items_fetched, trust_score,
                       error_msg, checked_at
                FROM feed_health_log f1
                WHERE checked_at = (
                    SELECT MAX(checked_at) FROM feed_health_log f2
                    WHERE f2.feed_url = f1.feed_url
                )
                ORDER BY failures DESC, feed_name
            """)
            cols = [d[0] for d in cur.description]
            rows = [dict(zip(cols, r)) for r in cur.fetchall()]
        else:
            rows = [dict(r) for r in conn.execute("""
                SELECT feed_name, feed_url, status, failures, items_fetched, trust_score,
                       error_msg, checked_at
                FROM feed_health_log f1
                WHERE checked_at = (
                    SELECT MAX(checked_at) FROM feed_health_log f2
                    WHERE f2.feed_url = f1.feed_url
                )
                ORDER BY failures DESC, feed_name
            """).fetchall()]
        return jsonify(rows)
    except Exception as e:
        _log.warning(f"[FeedHealth] DB read error: {e}")
        # Fall back to in-memory data
        all_feeds = list(RSS_FEEDS) + get_custom_feeds_from_db()
        result = []
        for name, url in all_feeds:
            fh = _feed_health.get(url, {})
            lo = fh.get('last_ok')
            result.append({'feed_name': name, 'feed_url': url,
                           'failures': fh.get('failures', 0),
                           'status': 'disabled' if fh.get('disabled') else 'ok' if lo else 'unknown',
                           'items_fetched': 0, 'trust_score': _get_source_trust(name),
                           'error_msg': '', 'checked_at': lo.isoformat() if lo else ''})
        result.sort(key=lambda x: (-x['failures'], x['feed_name']))
        return jsonify(result)
    finally:
        conn.close()

