@app.route('/api/topics/upload_excel', methods=['POST'])
def api_topics_upload_excel():
    u = session.get('user')
    if not u or u['role'].lower() != 'admin': return jsonify({"error":"Forbidden"}),403
    if 'file' not in request.files: return jsonify({"ok":False,"error":"No file"})
    f = request.files['file']
    try:
        if not EXCEL_OK: return jsonify({"ok":False,"error":"openpyxl not installed"})
        raw = io.BytesIO(f.read())
        wb = openpyxl.load_workbook(raw, data_only=True)
        ws = wb.active
        topics_list = []
        for row in ws.iter_rows(values_only=True):
            for cell in row:
                if cell and str(cell).strip():
                    topics_list.append(str(cell).strip())
        if not topics_list: return jsonify({"ok":False,"error":"No topics found in Excel"})
        conn = get_db(); added = 0
        for t in topics_list:
            try:
                if USE_MSSQL:
                    cur = conn.cursor()
                    cur.execute("IF NOT EXISTS(SELECT 1 FROM topics WHERE name=?) INSERT INTO topics(name,created_at) VALUES(?,?)",
                                 (t, t, datetime.now().isoformat()))
                else:
                    conn.execute("INSERT OR IGNORE INTO topics(name,created_at) VALUES(?,?)",
                                 (t, datetime.now().isoformat()))
                added += 1
            except: pass
        conn.commit(); conn.close()
        return jsonify({"ok":True,"added":added,"total":len(topics_list)})
    except Exception as e:
        return jsonify({"ok":False,"error":str(e)})

