# ─── ARTICLES ─────────────────────────────────────────────────────────────────
@app.route('/api/articles')
def api_articles():
    if not session.get('user'): return jsonify({"error":"not_logged_in"}),401
    conn=get_db()
    try:
        uid=session['user']['id']
        today=get_today_ist()
        if USE_MSSQL:
            cur=conn.cursor()
            cur.execute("SELECT COUNT(*) FROM topics");tc=cur.fetchone()[0]
        else:
            tc=conn.execute("SELECT COUNT(*) FROM topics").fetchone()[0]
        has_topics=tc>0
        # Only load articles within DATA_RETENTION_DAYS (30 days) — do NOT load older news
        cutoff_date = (datetime.now(timezone.utc) + timedelta(hours=5, minutes=30) - timedelta(days=DATA_RETENTION_DAYS)).strftime("%Y-%m-%d")
        if USE_MSSQL:
            topic_cond = "topics NOT IN ('[]','') AND topics IS NOT NULL" if has_topics else ""
            date_cond  = "pub_date_ist >= ?"
            if topic_cond:
                filt = f"WHERE {topic_cond} AND {date_cond}"
            else:
                filt = f"WHERE {date_cond}"
            filt_today = filt + " AND pub_date_ist LIKE ?"
            cur.execute(f"SELECT * FROM articles {filt} ORDER BY pub_date DESC", (cutoff_date,))
            cols=[d[0] for d in cur.description];all_rows=[dict(zip(cols,r)) for r in cur.fetchall()]
            cur.execute(f"SELECT * FROM articles {filt_today} ORDER BY pub_date DESC", (cutoff_date, today+'%',))
            today_rows=[dict(zip(cols,r)) for r in cur.fetchall()]
            cur.execute("SELECT article_id FROM favorites WHERE user_id=?",(uid,))
            fav_ids=[r[0] for r in cur.fetchall()]
        else:
            topic_cond = "topics!='[]' AND topics!=''" if has_topics else ""
            date_cond  = "pub_date_ist >= ?"
            if topic_cond:
                filt = f"WHERE {topic_cond} AND {date_cond}"
            else:
                filt = f"WHERE {date_cond}"
            filt_today = filt + " AND pub_date_ist LIKE ?"
            all_rows=[dict(r) for r in conn.execute(f"SELECT * FROM articles {filt} ORDER BY pub_date DESC", (cutoff_date,)).fetchall()]
            today_rows=[dict(r) for r in conn.execute(f"SELECT * FROM articles {filt_today} ORDER BY pub_date DESC", (cutoff_date, today+'%',)).fetchall()]
            fav_ids=[r['article_id'] for r in conn.execute("SELECT article_id FROM favorites WHERE user_id=?",(uid,)).fetchall()]

        # Load all remarks for fast lookup
        try:
            if USE_MSSQL:
                rc=conn.cursor(); rc.execute("SELECT article_id,remark,full_name,username,created_at FROM article_remarks")
                remarks_map={row[0]:{"remark":row[1],"full_name":row[2],"username":row[3],"created_at":row[4]} for row in rc.fetchall()}
            else:
                remarks_map={r['article_id']:{"remark":r['remark'],"full_name":r['full_name'],"username":r['username'],"created_at":r['created_at']} for r in conn.execute("SELECT article_id,remark,full_name,username,created_at FROM article_remarks").fetchall()}
        except Exception:
            remarks_map={}

        def proc(rows):
            result=[]
            for r in rows:
                d=dict(r)
                try: d['cities']=json.loads(d.get('cities') or '[]')
                except: d['cities']=[]
                try: d['topics']=json.loads(d.get('topics') or '[]')
                except: d['topics']=[]
                d['is_read']=bool(d.get('is_read',0))
                d['is_alert']=bool(d.get('is_alert',0))
                d['is_urgent']=bool(d.get('is_urgent',0))
                rm=remarks_map.get(d.get('id'))
                d['remark']=rm['remark'] if rm else ''
                d['remark_by']=(rm.get('full_name') or rm.get('username','')) if rm else ''
                d['remark_at']=rm['created_at'] if rm else ''
                result.append(d)
            return result

        all_p=proc(all_rows); today_p=proc(today_rows)

        # Topic aggregation for today — include full article_objs for frontend rendering
        td=defaultdict(lambda:{"count":0,"read":0,"unread":0,"positive":0,"negative":0,"neutral":0,"articles":[],"article_objs":[]})
        for r in today_p:
            for t in (r.get('topics') or []):
                td[t]["count"]+=1; td[t][r.get('sentiment','neutral')]+=1
                td[t]["read" if r.get('is_read') else "unread"]+=1
                td[t]["articles"].append((r.get('title') or '')[:80])
                td[t]["article_objs"].append(r)
        top20=sorted([{"topic":k,**v} for k,v in td.items()],key=lambda x:-x["count"])[:20]
        stats={
            "total":len(all_rows),"today":len(today_rows),
            "alerts":sum(1 for r in all_rows if r.get('priority')=='High' or r.get('is_urgent')),
            "high":sum(1 for r in all_rows if r.get('priority')=='High'),
            "medium":sum(1 for r in all_rows if r.get('priority')=='Medium'),
            "favs":len(fav_ids),
            "verified":sum(1 for r in all_rows if (r.get('ai_verified') or '').startswith('✅')),
        }
        global last_fetch_time
        lf=last_fetch_time.strftime("%Y-%m-%d %H:%M IST") if last_fetch_time else "Never"
        payload={"all":all_p,"today":today_p,"topics":top20,"stats":stats,
                 "fav_ids":fav_ids,"last_fetch":lf,
                 "db_type":"MSSQL" if USE_MSSQL else "SQLite"}
        # ETag: skip full JSON if article count & verified count unchanged
        import hashlib as _hl2
        etag_raw = f"{lf}|{stats.get('total',0)}|{stats.get('verified',0)}|{stats.get('today',0)}"
        etag = _hl2.md5(etag_raw.encode()).hexdigest()[:16]
        if request.headers.get('If-None-Match') == etag:
            return '', 304
        resp = jsonify(payload)
        resp.headers['ETag'] = etag
        resp.headers['Cache-Control'] = 'no-cache'
        return resp
    finally: conn.close()

