@app.route('/api/articles/bycity')
def api_articles_bycity():
    """Return all articles for a given city/location — used by the Map news panel."""
    if not session.get('user'): return jsonify({"error":"not_logged_in"}), 401
    city_param = request.args.get('city','').strip().lower()
    if not city_param:
        return jsonify({"all":[], "today":[]})
    conn = get_db()
    try:
        uid = session['user']['id']
        today = get_today_ist()
        is_india = city_param == 'india'
        if USE_MSSQL:
            cur = conn.cursor()
            cur.execute("SELECT * FROM articles ORDER BY pub_date DESC")
            cols = [d[0] for d in cur.description]
            all_rows = [dict(zip(cols, r)) for r in cur.fetchall()]
            cur.execute("SELECT article_id FROM favorites WHERE user_id=?", (uid,))
            fav_ids = [r[0] for r in cur.fetchall()]
        else:
            all_rows = [dict(r) for r in conn.execute(
                "SELECT * FROM articles ORDER BY pub_date DESC").fetchall()]
            fav_ids = [r['article_id'] for r in conn.execute(
                "SELECT article_id FROM favorites WHERE user_id=?", (uid,)).fetchall()]
        # Load remarks
        try:
            if USE_MSSQL:
                rc = conn.cursor()
                rc.execute("SELECT article_id,remark,full_name,username,created_at FROM article_remarks")
                remarks_map = {row[0]:{"remark":row[1],"full_name":row[2],"username":row[3],"created_at":row[4]} for row in rc.fetchall()}
            else:
                remarks_map = {r['article_id']:{"remark":r['remark'],"full_name":r['full_name'],"username":r['username'],"created_at":r['created_at']}
                               for r in conn.execute("SELECT article_id,remark,full_name,username,created_at FROM article_remarks").fetchall()}
        except Exception:
            remarks_map = {}
        result_all = []
        result_today = []
        for r in all_rows:
            d = dict(r)
            try: cities = json.loads(d.get('cities') or '[]')
            except: cities = []
            try: d['topics'] = json.loads(d.get('topics') or '[]')
            except: d['topics'] = []
            d['cities'] = cities
            # City match
            if is_india:
                match = 'india' in [c.lower() for c in cities] or len(cities) == 0
            else:
                cn = city_param.replace(' ', '')
                match = any(
                    c.lower().replace('state:','').strip() == city_param or
                    c.lower().replace('state:','').strip().replace(' ','') == cn
                    for c in cities
                )
            if not match:
                continue
            d['is_read'] = bool(d.get('is_read', 0))
            d['is_alert'] = bool(d.get('is_alert', 0))
            d['is_urgent'] = bool(d.get('is_urgent', 0))
            rm = remarks_map.get(d.get('id'))
            d['remark'] = rm['remark'] if rm else ''
            d['remark_by'] = (rm.get('full_name') or rm.get('username','')) if rm else ''
            d['remark_at'] = rm['created_at'] if rm else ''
            result_all.append(d)
            if (d.get('pub_date_ist') or '').startswith(today):
                result_today.append(d)
        return jsonify({"all": result_all, "today": result_today})
    finally:
        conn.close()

@app.route('/api/pdf-debug')
def pdf_debug():
    """Diagnostic endpoint — shows Python/fpdf environment info to fix PDF export issues."""
