@app.route('/api/pivot')
def api_pivot():
    if not session.get('user'): return jsonify({}),401
    conn=get_db()
    try:
        today=get_today_ist()
        if USE_MSSQL:
            cur=conn.cursor()
            cur.execute("SELECT COUNT(*) FROM topics");tc=cur.fetchone()[0]
        else:
            tc=conn.execute("SELECT COUNT(*) FROM topics").fetchone()[0]
        filt="WHERE topics!='[]' AND topics!=''" if tc>0 else ""
        filt_today=(filt+" AND " if filt else "WHERE ")+"pub_date_ist LIKE ?"
        if USE_MSSQL:
            cur.execute(f"SELECT * FROM articles {filt}")
            cols=[d[0] for d in cur.description];all_rows=[dict(zip(cols,r)) for r in cur.fetchall()]
            cur.execute(f"SELECT * FROM articles {filt_today}",(today+'%',))
            today_rows=[dict(zip(cols,r)) for r in cur.fetchall()]
        else:
            all_rows=[dict(r) for r in conn.execute(f"SELECT * FROM articles {filt}").fetchall()]
            today_rows=[dict(r) for r in conn.execute(f"SELECT * FROM articles {filt_today}",(today+'%',)).fetchall()]
        def mkpiv(rows):
            p=defaultdict(lambda:{"total":0,"positive":0,"negative":0,"neutral":0,"read":0,"unread":0})
            for r in rows:
                s=r['source'];p[s]["total"]+=1;p[s][r.get('sentiment','neutral')]+=1
                p[s]["read" if r.get('is_read') else "unread"]+=1
            return [{"source":k,**v} for k,v in sorted(p.items())]
        by_cat=defaultdict(lambda:{"total":0,"high":0,"medium":0,"low":0})
        for r in today_rows:
            cat=r.get('category','Other');by_cat[cat]["total"]+=1
            pri=r.get('priority','Low')
            if pri=='High':by_cat[cat]["high"]+=1
            elif pri=='Medium':by_cat[cat]["medium"]+=1
            else:by_cat[cat]["low"]+=1
        # Topics pivot
        def mkpiv_topics(rows):
            td = defaultdict(lambda:{"count":0,"read":0,"unread":0,"positive":0,"negative":0,"neutral":0})
            for r in rows:
                for t in json.loads(r.get('topics') or '[]'):
                    td[t]["count"] += 1
                    td[t][r.get('sentiment','neutral')] += 1
                    td[t]["read" if r.get('is_read') else "unread"] += 1
            return sorted([{"topic":k,**v} for k,v in td.items()], key=lambda x:-x["count"])[:50]

        return jsonify({"all":mkpiv(all_rows),"today":mkpiv(today_rows),
                        "by_cat":[{"category":k,**v} for k,v in sorted(by_cat.items())],
                        "topics_all":mkpiv_topics(all_rows),
                        "topics_today":mkpiv_topics(today_rows)})
    finally: conn.close()

