@app.route('/api/topics', methods=['POST'])
def api_post_topics():
    u=session.get('user')
    if not u or u['role'].lower()!='admin': return jsonify({"error":"Forbidden"}),403
    new_topics=[t.strip() for t in (request.json.get('topics') or []) if t.strip()]
    conn=get_db(); added=0
    try:
        for t in new_topics:
            try:
                if USE_MSSQL:
                    conn.cursor().execute("IF NOT EXISTS(SELECT 1 FROM topics WHERE name=?) INSERT INTO topics(name,created_at) VALUES(?,?)",(t,t,datetime.now().isoformat()))
                else:
                    conn.execute("INSERT OR IGNORE INTO topics(name,created_at) VALUES(?,?)",(t,datetime.now().isoformat()))
                added+=1
            except: pass
        conn.commit()
        if USE_MSSQL:
            cur=conn.cursor();cur.execute("SELECT COUNT(*) FROM topics");total=cur.fetchone()[0]
        else:
            total=conn.execute("SELECT COUNT(*) FROM topics").fetchone()[0]
        return jsonify({"count":total,"added":added})
    finally: conn.close()

