@app.route('/api/topics/reprocess', methods=['POST'])
def api_reprocess_topics():
    u=session.get('user')
    if not u or u['role'].lower()!='admin': return jsonify({"error":"Forbidden"}),403
    conn=get_db()
    try:
        if USE_MSSQL:
            cur=conn.cursor();cur.execute("SELECT name FROM topics");topics=[r[0] for r in cur.fetchall()]
            cur.execute("SELECT id,title,description FROM articles");rows=cur.fetchall()
            for r in rows:
                full=(r[1] or '')+' '+(r[2] or '')
                matched=[t for t in topics if topic_matches(t,full)]
                conn.cursor().execute("UPDATE articles SET topics=? WHERE id=?",(json.dumps(matched),r[0]))
        else:
            topics=[r['name'] for r in conn.execute("SELECT name FROM topics").fetchall()]
            rows=conn.execute("SELECT id,title,description FROM articles").fetchall()
            for r in rows:
                full=(r['title'] or '')+' '+(r['description'] or '')
                matched=[t for t in topics if topic_matches(t,full)]
                conn.execute("UPDATE articles SET topics=? WHERE id=?",(json.dumps(matched),r['id']))
        conn.commit();return jsonify({"count":len(rows)})
    finally: conn.close()

