@app.route('/api/export_excel')
def api_export_excel():
    if not session.get('user'): return jsonify({"error":"Not logged in"}),401
    if not EXCEL_OK: return "openpyxl not installed",500
    # Active filters from frontend
    f_topic = (request.args.get('topic') or '').strip()
    f_q     = (request.args.get('q') or '').lower().strip()
    f_src   = (request.args.get('src') or '').strip()
    f_pri   = (request.args.get('pri') or '').strip()
    f_cat   = (request.args.get('cat') or '').strip()
    conn=get_db()
    try:
        today=get_today_ist()
        if USE_MSSQL:
            cur=conn.cursor();cur.execute("SELECT * FROM articles ORDER BY pub_date DESC")
            cols=[d[0] for d in cur.description];all_rows=[dict(zip(cols,r)) for r in cur.fetchall()]
            cur.execute("SELECT * FROM articles WHERE pub_date_ist LIKE ? ORDER BY pub_date DESC",(today+'%',))
            today_rows=[dict(zip(cols,r)) for r in cur.fetchall()]
        else:
            all_rows=[dict(r) for r in conn.execute("SELECT * FROM articles ORDER BY pub_date DESC").fetchall()]
            today_rows=[dict(r) for r in conn.execute("SELECT * FROM articles WHERE pub_date_ist LIKE ? ORDER BY pub_date DESC",(today+'%',)).fetchall()]
    finally: conn.close()
    def proc(rows):
        out = []
        for _r in rows:
            r = dict(_r) if not isinstance(_r, dict) else dict(_r)
            try: r['cities'] = json.loads(r.get('cities') or '[]')
            except: r['cities'] = []
            try: r['topics'] = json.loads(r.get('topics') or '[]')
            except: r['topics'] = []
            r['is_read'] = bool(r.get('is_read', 0))
            out.append(r)
        return out
    def apply_filters(rows):
        out = []
        for r in rows:
            if f_topic and f_topic not in (r.get('topics') or []): continue
            if f_q:
                hay = ((r.get('title') or '') + ' ' + (r.get('description') or '') + ' ' + (r.get('source') or '')).lower()
                if f_q not in hay: continue
            if f_src and r.get('source') != f_src: continue
            if f_pri and r.get('priority') != f_pri: continue
            if f_cat and r.get('category') != f_cat: continue
            out.append(r)
        return out
    all_p=proc(all_rows); today_p=proc(today_rows)
    has_filter = any([f_topic, f_q, f_src, f_pri, f_cat])
    if has_filter:
        all_p = apply_filters(all_p)
        today_p = apply_filters(today_p)
    td=defaultdict(lambda:{"count":0,"read":0,"unread":0})
    for r in today_p:
        for t in r.get('topics',[]):
            td[t]["count"]+=1;td[t]["read" if r.get('is_read') else "unread"]+=1
    top20=sorted([{"topic":k,**v} for k,v in td.items()],key=lambda x:-x["count"])[:20]
    def mkpiv(rows):
        p=defaultdict(lambda:{"total":0,"positive":0,"negative":0,"neutral":0,"read":0,"unread":0})
        for r in rows: s=r['source'];p[s]["total"]+=1;p[s][r.get('sentiment','neutral')]+=1;p[s]["read" if r.get('is_read') else "unread"]+=1
        return [{"source":k,**v} for k,v in sorted(p.items())]
    logo_b64=get_export_logo()
    def mkpiv_topics_ex(rows):
        td=defaultdict(lambda:{"count":0,"read":0,"unread":0,"positive":0,"negative":0,"neutral":0})
        for r in rows:
            for t in r.get('topics',[]):
                td[t]["count"]+=1; td[t][r.get('sentiment','neutral')]+=1
                td[t]["read" if r.get('is_read') else "unread"]+=1
        return sorted([{"topic":k,**v} for k,v in td.items()],key=lambda x:-x["count"])[:50]
    pivot_topics={'all':mkpiv_topics_ex(all_p),'today':mkpiv_topics_ex(today_p)}
    alerts_p = [r for r in all_p if r.get('priority')=='High' or r.get('is_urgent')]
    try:
        buf=make_excel(all_p,today_p,top20,mkpiv(all_p),mkpiv(today_p),logo_b64=None,pivot_topics=pivot_topics,rows_alerts=alerts_p)
    except Exception as _xl_err:
        _log.error(f"[Excel Export] make_excel error: {_xl_err}")
        import traceback; traceback.print_exc()
        return f"Excel export error: {_xl_err}", 500
    if not buf: return "Export failed — openpyxl not installed or internal error",500
    return send_file(buf,as_attachment=True,
                     download_name=f"JCF_News_{datetime.now().strftime('%Y%m%d_%H%M%S_%f')}.xlsx",
                     mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet')

@app.route('/api/export/<section>/<fmt>')
def api_export(section, fmt):
    if not session.get('user'): return redirect('/')
    # Active filters passed from frontend
    f_topic = (request.args.get('topic') or '').strip()
    f_q     = (request.args.get('q') or '').lower().strip()
    f_src   = (request.args.get('src') or '').strip()
    f_pri   = (request.args.get('pri') or '').strip()
    f_cat   = (request.args.get('cat') or '').strip()
    conn=get_db()
    try:
        today=get_today_ist();uid=session['user']['id']
        if USE_MSSQL:
            cur=conn.cursor();cur.execute("SELECT * FROM articles ORDER BY pub_date DESC")
            cols=[d[0] for d in cur.description];all_rows=[dict(zip(cols,r)) for r in cur.fetchall()]
            cur.execute("SELECT * FROM articles WHERE pub_date_ist LIKE ? ORDER BY pub_date DESC",(today+'%',))
            today_rows=[dict(zip(cols,r)) for r in cur.fetchall()]
            cur.execute("SELECT article_id FROM favorites WHERE user_id=?",(uid,));fav_ids=[r[0] for r in cur.fetchall()]
        else:
            all_rows=[dict(r) for r in conn.execute("SELECT * FROM articles ORDER BY pub_date DESC").fetchall()]
            today_rows=[dict(r) for r in conn.execute("SELECT * FROM articles WHERE pub_date_ist LIKE ? ORDER BY pub_date DESC",(today+'%',)).fetchall()]
            fav_ids=[r['article_id'] for r in conn.execute("SELECT article_id FROM favorites WHERE user_id=?",(uid,)).fetchall()]
    finally: conn.close()
    def proc(rows):
        for r in rows:
            try: r['cities']=json.loads(r.get('cities') or '[]')
            except: r['cities']=[]
            try: r['topics']=json.loads(r.get('topics') or '[]')
            except: r['topics']=[]
        return rows
    def apply_filters(rows):
        """Apply topic/keyword/source/priority/category filters if any are active."""
        out = []
        for r in rows:
            if f_topic and f_topic not in (r.get('topics') or []):
                continue
            if f_q:
                haystack = ((r.get('title') or '') + ' ' + (r.get('description') or '') + ' ' + (r.get('source') or '')).lower()
                if f_q not in haystack:
                    continue
            if f_src and r.get('source') != f_src:
                continue
            if f_pri and r.get('priority') != f_pri:
                continue
            if f_cat and r.get('category') != f_cat:
                continue
            out.append(r)
        return out
    all_p=proc(all_rows); today_p=proc(today_rows)
    fav_p=[r for r in all_p if r.get('id') in fav_ids]
    alerts_p=[r for r in all_p if r.get('priority')=='High' or r.get('is_urgent')]
    data_map={"all":all_p,"today":today_p,"fav":fav_p,"alerts":alerts_p,"cat":all_p}
    rows=data_map.get(section, all_p)
    # Apply filters if any active (topic search exports only filtered news)
    has_filter = any([f_topic, f_q, f_src, f_pri, f_cat])
    if has_filter:
        rows = apply_filters(rows)
    # Build title showing active filters
    filter_label = []
    if f_topic: filter_label.append(f"Topic:{f_topic}")
    if f_q: filter_label.append(f"Search:{f_q}")
    if f_src: filter_label.append(f"Source:{f_src}")
    if f_pri: filter_label.append(f"Priority:{f_pri}")
    if f_cat: filter_label.append(f"Category:{f_cat}")
    _section_titles = {
        "all":        "All Articles",
        "today":      "Today's News",
        "topics":     "Today Top 20 Topics",
        "cat":        "Category Wise News",
        "fav":        "Favourited News",
        "alerts":     "High Priority Alerts",
        "readnews":   "Read Latest News",
        "readtoday":  "Read Today's News",
        "readtopics": "Read Top-20 Topics",
    }
    title_text = f"JCF — {_section_titles.get(section, section.title())}"
    if filter_label: title_text += f" | {', '.join(filter_label)}"
    # Build a filesystem-safe version of the title for filenames
    _safe_title = re.sub(r'[^\w\s-]', '', title_text).strip().replace(' ', '_').replace('—', '').replace('__', '_').strip('_')
    logo_b64 = get_export_logo()
    if fmt=='csv':
        csv_bytes=make_csv(rows, logo_b64)
        return Response(csv_bytes,mimetype='text/csv',
                        headers={"Content-Disposition":f"attachment;filename={_safe_title}_{datetime.now().strftime('%Y%m%d_%H%M%S_%f')}.csv"})
    else:
        try:
            u = session.get('user') or {}
            _read_by = u.get('full_name') or u.get('username') or ''
            _is_read_section = section in ('readnews', 'readtoday', 'readtopics')
            _has_read = _is_read_section or any(r.get('is_read') for r in rows)
            pdf_bytes, mime = make_pdf_simple(rows, title_text, logo_b64, include_read_by=_has_read, read_by_name=_read_by, section=section)
        except Exception as pdf_err:
            import sys, os
            diag = [
                f"PDF export failed: {pdf_err}",
                f"",
                f"=== RUN THIS COMMAND IN POWERSHELL TO FIX ===",
                f'& "{sys.executable}" -m pip install fpdf2',
                f"",
                f"=== DIAGNOSTIC INFO ===",
                f"Python executable: {sys.executable}",
                f"Python version: {sys.version.split()[0]}",
                f"PDF_OK={PDF_OK}, fpdf2={_fpdf2}",
                f"",
                f"After running the pip command above, restart the app.",
                f"Or visit http://localhost:5000/api/pdf-debug for full details.",
            ]
            print(f"[PDF Export] Error: {pdf_err}")
            return Response("\n".join(diag), mimetype="text/plain", status=500)
        return Response(pdf_bytes, mimetype='application/pdf',
                        headers={"Content-Disposition":f"attachment;filename={_safe_title}_{datetime.now().strftime('%Y%m%d_%H%M%S_%f')}.pdf"})


@app.route('/api/export_topics_pdf')
def api_export_topics_pdf():
    """Export Top 20 Read Topics as a PDF with Read By column."""
    if not session.get('user'): return redirect('/')
    conn = get_db()
    try:
        today = get_today_ist(); uid = session['user']['id']
        if USE_MSSQL:
            cur = conn.cursor()
            cur.execute("SELECT * FROM articles WHERE pub_date_ist LIKE ? ORDER BY pub_date DESC", (today + '%',))
            cols = [d[0] for d in cur.description]
            today_rows = [dict(zip(cols, r)) for r in cur.fetchall()]
        else:
            today_rows = [dict(r) for r in conn.execute(
                "SELECT * FROM articles WHERE pub_date_ist LIKE ? ORDER BY pub_date DESC", (today + '%',)).fetchall()]
    finally:
        conn.close()

    for r in today_rows:
        try: r['topics'] = json.loads(r.get('topics') or '[]')
        except: r['topics'] = []
        r['is_read'] = bool(r.get('is_read', 0))

    # Build top20 from today's articles
    td = {}
    for r in today_rows:
        for t in (r.get('topics') or []):
            if t not in td: td[t] = {'count': 0, 'read': 0, 'unread': 0, 'positive': 0, 'negative': 0}
            td[t]['count'] += 1
            if r.get('is_read'): td[t]['read'] += 1
            else: td[t]['unread'] += 1
            s = r.get('sentiment', 'neutral')
            if s == 'positive': td[t]['positive'] += 1
            elif s == 'negative': td[t]['negative'] += 1
    top20 = sorted([{'topic': k, **v} for k, v in td.items()], key=lambda x: -x['count'])[:20]
    top20_read = [t for t in top20 if t.get('read', 0) > 0]

    u = session.get('user') or {}
    read_by_name = u.get('full_name') or u.get('username') or ''
    logo_b64 = get_export_logo()

    try:
        pdf_bytes, mime = make_pdf_topics(
            top20_read if top20_read else top20,
            "JCF — Top 20 Read Topics Today",
            logo_b64, read_by_name=read_by_name
        )
    except Exception as e:
        return Response(f"PDF error: {e}", mimetype='text/plain', status=500)
    return Response(pdf_bytes, mimetype='application/pdf',
                    headers={"Content-Disposition": f"attachment;filename=JCF_Top20_Read_Topics_{datetime.now().strftime('%Y%m%d_%H%M%S_%f')}.pdf"})

@app.route('/api/network_info')
def api_network_info():
    """Return all LAN IP addresses so phones can connect via same Wi-Fi."""
    if not session.get('user'): return jsonify({"urls": [], "port": 5012}), 401
    import socket
    ips = []
    try:
        # Get all network interfaces
        hostname = socket.gethostname()
        # Primary method: connect to external to find outbound IP
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            s.connect(("8.8.8.8", 80))
            primary_ip = s.getsockname()[0]
            s.close()
            if primary_ip and not primary_ip.startswith("127."):
                ips.append(primary_ip)
        except: pass
        # Secondary: getaddrinfo
        try:
            for info in socket.getaddrinfo(hostname, None):
                ip = info[4][0]
                if ip and not ip.startswith("127.") and ":" not in ip and ip not in ips:
                    ips.append(ip)
        except: pass
    except Exception as e:
        pass
    port = 5012
    urls = [{"ip": ip, "url": f"http://{ip}:{port}"} for ip in ips]
    if not urls:
        urls = [{"ip": "127.0.0.1", "url": f"http://127.0.0.1:{port}"}]
    return jsonify({"urls": urls, "port": port})

@app.route('/api/clear_db', methods=['POST'])
def api_clear_db():
    u=session.get('user')
    if not u or u['role'].lower()!='admin': return jsonify({"error":"Forbidden"}),403
    conn=get_db()
    try:
        if USE_MSSQL: conn.cursor().execute("DELETE FROM articles")
        else: conn.execute("DELETE FROM articles")
        conn.commit();return jsonify({"ok":True})
    finally: conn.close()

