# REMARK API
# ══════════════════════════════════════════════════════════════════════════════
@app.route('/api/remark/<aid>', methods=['POST'])
def api_save_remark(aid):
    u = session.get('user')
    if not u: return jsonify({"error":"not_logged_in"}),401
    remark = (request.json or {}).get('remark','').strip()[:200]
    if not remark: return jsonify({"ok":False,"error":"Empty remark"}),400
    conn = get_db()
    try:
        # Check existing remark
        if USE_MSSQL:
            cur = conn.cursor(); cur.execute("SELECT id,user_id FROM article_remarks WHERE article_id=?",(aid,))
            existing = cur.fetchone()
        else:
            existing = conn.execute("SELECT id,user_id FROM article_remarks WHERE article_id=?",(aid,)).fetchone()
        if existing:
            if u['role'].lower() != 'admin':
                return jsonify({"ok":False,"error":"only_admin_can_rewrite"})
            # Admin rewrite
            if USE_MSSQL:
                cur.execute("UPDATE article_remarks SET remark=?,full_name=?,username=?,updated_at=? WHERE article_id=?",
                           (remark, u.get('full_name',''), u['username'], now_ist(), aid))
            else:
                conn.execute("UPDATE article_remarks SET remark=?,full_name=?,username=?,updated_at=? WHERE article_id=?",
                            (remark, u.get('full_name',''), u['username'], now_ist(), aid))
        else:
            if USE_MSSQL:
                cur.execute("INSERT INTO article_remarks(article_id,user_id,username,full_name,remark,created_at,updated_at) VALUES(?,?,?,?,?,?,?)",
                           (aid, u['id'], u['username'], u.get('full_name',''), remark, now_ist(), now_ist()))
            else:
                conn.execute("INSERT INTO article_remarks(article_id,user_id,username,full_name,remark,created_at,updated_at) VALUES(?,?,?,?,?,?,?)",
                            (aid, u['id'], u['username'], u.get('full_name',''), remark, now_ist(), now_ist()))
        conn.commit()
        return jsonify({"ok":True})
    finally: conn.close()

