@app.route('/api/article/<aid>', methods=['DELETE'])
def api_delete_article(aid):
    """Delete a single article (admin only). Also cleans up remarks and favorites."""
    u = session.get('user')
    if not u or u['role'].lower() != 'admin': return jsonify({"error":"Forbidden"}),403
    conn = get_db()
    try:
        if USE_MSSQL:
            cur = conn.cursor()
            cur.execute("DELETE FROM article_remarks WHERE article_id=?", (aid,))
            cur.execute("DELETE FROM favorites WHERE article_id=?", (aid,))
            cur.execute("DELETE FROM news_assignments WHERE article_id=?", (aid,))
            cur.execute("DELETE FROM articles WHERE id=?", (aid,))
        else:
            conn.execute("DELETE FROM article_remarks WHERE article_id=?", (aid,))
            conn.execute("DELETE FROM favorites WHERE article_id=?", (aid,))
            conn.execute("DELETE FROM news_assignments WHERE article_id=?", (aid,))
            conn.execute("DELETE FROM articles WHERE id=?", (aid,))
        conn.commit()
        return jsonify({"ok": True})
    except Exception as e:
        _log.error(f"[DeleteArticle] {e}")
        return jsonify({"error": str(e)}), 500
    finally: conn.close()

# ══════════════════════════════════════════════════════════════════════════════
# CHAT API — user-to-user, max 10 messages per conversation kept
# ══════════════════════════════════════════════════════════════════════════════
@app.route('/api/chat/users')
def api_chat_users():
    u = session.get('user')
    if not u: return jsonify({"error":"not_logged_in"}),401
    me = u['id']
    my_role = (u.get('role') or 'viewer').lower()
    my_uname = (u.get('username') or '').lower()
    conn = get_db()
    try:
        if USE_MSSQL:
            cur = conn.cursor()
            # icomply sees ALL users (no filter)
            # admins see all users except icomply (can chat admin→user)
            # viewers/editors: see icomply + admins so they can receive & reply
            if my_uname == 'icomply' or my_role == 'admin':
                cur.execute("SELECT id,username,full_name,role FROM users WHERE is_active=1 AND id!=? ORDER BY full_name,username", (me,))
            else:
                cur.execute("SELECT id,username,full_name,role FROM users WHERE is_active=1 AND id!=? AND (role='admin' OR username='icomply') ORDER BY full_name,username", (me,))
            cols=[d[0] for d in cur.description]; rows=[dict(zip(cols,r)) for r in cur.fetchall()]
            cur.execute("SELECT from_user_id, COUNT(*) AS cnt FROM chat_messages WHERE to_user_id=? AND is_read=0 GROUP BY from_user_id", (me,))
            unread_map={r[0]:r[1] for r in cur.fetchall()}
        else:
            if my_uname == 'icomply' or my_role == 'admin':
                rows=[dict(r) for r in conn.execute("SELECT id,username,full_name,role FROM users WHERE is_active=1 AND id!=? ORDER BY full_name,username",(me,)).fetchall()]
            else:
                rows=[dict(r) for r in conn.execute("SELECT id,username,full_name,role FROM users WHERE is_active=1 AND id!=? AND (role='admin' OR username='icomply') ORDER BY full_name,username",(me,)).fetchall()]
            unread_rows=conn.execute("SELECT from_user_id, COUNT(*) AS cnt FROM chat_messages WHERE to_user_id=? AND is_read=0 GROUP BY from_user_id",(me,)).fetchall()
            unread_map={r[0]:r[1] for r in unread_rows}
        for row in rows:
            row['unread_count'] = unread_map.get(row['id'], 0)
        # Sort: users with unread first
        rows.sort(key=lambda r: (-r['unread_count'], (r['full_name'] or r['username']).lower()))
        total_unread = sum(unread_map.values())
        return jsonify({"users": rows, "total_unread": total_unread})
    finally: conn.close()

@app.route('/api/chat/history')
def api_chat_history():
    u = session.get('user')
    if not u: return jsonify({"error":"not_logged_in"}),401
    with_uid = request.args.get('with','')
    if not with_uid: return jsonify({"messages":[]})
    me = u['id']
    conn = get_db()
    try:
        sql = """SELECT cm.id,cm.from_user_id,cm.to_user_id,cm.message,cm.article_id,cm.created_at,
                        uf.full_name AS from_name,uf.username AS from_username,
                        a.link AS article_link,a.title AS article_title
                 FROM chat_messages cm
                 LEFT JOIN users uf ON uf.id=cm.from_user_id
                 LEFT JOIN articles a ON a.id=cm.article_id
                 WHERE (cm.from_user_id=? AND cm.to_user_id=?) OR (cm.from_user_id=? AND cm.to_user_id=?)
                 ORDER BY cm.id DESC"""
        if USE_MSSQL:
            cur = conn.cursor(); cur.execute(sql,(me,with_uid,with_uid,me))
            cols=[d[0] for d in cur.description]; rows=[dict(zip(cols,r)) for r in cur.fetchall()]
        else:
            rows=[dict(r) for r in conn.execute(sql,(me,with_uid,with_uid,me)).fetchall()]
        rows = rows[:10]; rows.reverse()
        # Mark messages from the other user as read
        if USE_MSSQL:
            conn.cursor().execute("UPDATE chat_messages SET is_read=1 WHERE from_user_id=? AND to_user_id=? AND is_read=0", (int(with_uid), me))
        else:
            conn.execute("UPDATE chat_messages SET is_read=1 WHERE from_user_id=? AND to_user_id=? AND is_read=0", (int(with_uid), me))
        conn.commit()
        return jsonify({"messages": rows})
    finally: conn.close()

@app.route('/api/chat/unread_count')
def api_chat_unread_count():
    u = session.get('user')
    if not u: return jsonify({"count": 0}), 401
    me = u['id']
    conn = get_db()
    try:
        if USE_MSSQL:
            cur = conn.cursor()
            cur.execute("SELECT COUNT(*) FROM chat_messages WHERE to_user_id=? AND is_read=0", (me,))
            cnt = cur.fetchone()[0]
        else:
            row = conn.execute("SELECT COUNT(*) as cnt FROM chat_messages WHERE to_user_id=? AND is_read=0", (me,)).fetchone()
            cnt = row[0] if row else 0
        return jsonify({"count": cnt})
    finally: conn.close()

@app.route('/api/chat/send', methods=['POST'])
def api_chat_send():
    u = session.get('user')
    if not u: return jsonify({"error":"not_logged_in"}),401
    data = request.json or {}
    to_uid = data.get('to'); message = (data.get('message') or '').strip()[:500]
    article_id = data.get('article_id') or None
    if not to_uid or not message: return jsonify({"ok":False,"error":"Missing fields"}),400
    me = u['id']
    conn = get_db()
    try:
        if USE_MSSQL:
            cur = conn.cursor()
            cur.execute("INSERT INTO chat_messages(from_user_id,to_user_id,message,article_id,created_at) VALUES(?,?,?,?,?)",
                        (me,to_uid,message,article_id,now_ist()))
            # Prune: keep only latest 10 per conversation pair
            cur.execute("""DELETE FROM chat_messages WHERE id NOT IN (
                SELECT TOP 10 id FROM chat_messages
                WHERE (from_user_id=? AND to_user_id=?) OR (from_user_id=? AND to_user_id=?)
                ORDER BY id DESC)
                AND ((from_user_id=? AND to_user_id=?) OR (from_user_id=? AND to_user_id=?))""",
                (me,to_uid,to_uid,me,me,to_uid,to_uid,me))
        else:
            conn.execute("INSERT INTO chat_messages(from_user_id,to_user_id,message,article_id,created_at) VALUES(?,?,?,?,?)",
                         (me,to_uid,message,article_id,now_ist()))
            conn.execute("""DELETE FROM chat_messages WHERE id NOT IN (
                SELECT id FROM chat_messages
                WHERE (from_user_id=? AND to_user_id=?) OR (from_user_id=? AND to_user_id=?)
                ORDER BY id DESC LIMIT 10)
                AND ((from_user_id=? AND to_user_id=?) OR (from_user_id=? AND to_user_id=?))""",
                (me,to_uid,to_uid,me,me,to_uid,to_uid,me))
        # Notify recipient
        notify_body = f"💬 {u.get('full_name') or u['username']}: {message[:80]}"
        if USE_MSSQL:
            conn.cursor().execute("INSERT INTO notifications(user_id,title,body,priority,is_read,created_at) VALUES(?,?,?,?,0,?)",
                                  (to_uid,'New Chat Message',notify_body,'Low',now_ist()))
        else:
            conn.execute("INSERT INTO notifications(user_id,title,body,priority,is_read,created_at) VALUES(?,?,?,?,0,?)",
                         (to_uid,'New Chat Message',notify_body,'Low',now_ist()))
        conn.commit()
        return jsonify({"ok":True})
    finally: conn.close()

# ══════════════════════════════════════════════════════════════════════════════
# ASSIGN NEWS API (admin only)
# ══════════════════════════════════════════════════════════════════════════════
@app.route('/api/assign_news', methods=['POST'])
def api_assign_news():
    u = session.get('user')
    my_uname = (u.get('username') or '').lower()
    if not u or (u['role'].lower() != 'admin' and my_uname != 'icomply'): return jsonify({"error":"Forbidden"}),403
    data = request.json or {}
    article_id = data.get('article_id'); to_uid = data.get('to')
    note = (data.get('note') or '').strip()[:300]
    if not article_id or not to_uid: return jsonify({"ok":False,"error":"Missing fields"}),400
    me = u['id']
    conn = get_db()
    try:
        if USE_MSSQL:
            cur = conn.cursor(); cur.execute("SELECT title FROM articles WHERE id=?",(article_id,))
            row = cur.fetchone(); art_title = row[0] if row else 'News Article'
            cur.execute("INSERT INTO news_assignments(article_id,assigned_by,assigned_to,assigned_at,note) VALUES(?,?,?,?,?)",
                        (article_id,me,to_uid,now_ist(),note))
        else:
            row = conn.execute("SELECT title FROM articles WHERE id=?",(article_id,)).fetchone()
            art_title = row['title'] if row else 'News Article'
            conn.execute("INSERT INTO news_assignments(article_id,assigned_by,assigned_to,assigned_at,note) VALUES(?,?,?,?,?)",
                         (article_id,me,to_uid,now_ist(),note))
        name = u.get('full_name') or u['username']
        notif = f"📰 Assigned by {name}: {art_title[:100]}"
        if note: notif += f"\nNote: {note}"
        if USE_MSSQL:
            conn.cursor().execute("INSERT INTO notifications(user_id,title,body,priority,is_read,created_at) VALUES(?,?,?,?,0,?)",
                                  (to_uid,'News Assigned to You',notif,'Medium',now_ist()))
        else:
            conn.execute("INSERT INTO notifications(user_id,title,body,priority,is_read,created_at) VALUES(?,?,?,?,0,?)",
                         (to_uid,'News Assigned to You',notif,'Medium',now_ist()))
        conn.commit()
        return jsonify({"ok":True})
    finally: conn.close()


